import * as React from "react";
import { type DialogProps } from "@radix-ui/react-dialog";
import { Command as CommandPrimitive } from "cmdk";
import { Search } from "lucide-react";

import { cn } from "@/lib/utils";
import { Dialog, DialogContent } from "@/components/ui/dialog";

const Command = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive>
>(({ className, ...props }, ref) => (
  <CommandPrimitive
    ref={ref}
    className={cn(
      "flex h-full w-full flex-col overflow-hidden rounded-md bg-popover text-popover-foreground",
      className,
    )}
    {...props}
  />
));
Command.displayName = CommandPrimitive.displayName;

interface CommandDialogProps extends DialogProps {}

const CommandDialog = ({ children, ...props }: CommandDialogProps) => {
  return (
    <Dialog {...props}>
      <DialogContent className="overflow-hidden p-0 shadow-lg">
        <Command className="[&_[cmdk-group-heading]]:px-2 [&_[cmdk-group-heading]]:font-medium [&_[cmdk-group-heading]]:text-muted-foreground [&_[cmdk-group]:not([hidden])_~[cmdk-group]]:pt-0 [&_[cmdk-group]]:px-2 [&_[cmdk-input-wrapper]_svg]:h-5 [&_[cmdk-input-wrapper]_svg]:w-5 [&_[cmdk-input]]:h-12 [&_[cmdk-item]]:px-2 [&_[cmdk-item]]:py-3 [&_[cmdk-item]_svg]:h-5 [&_[cmdk-item]_svg]:w-5">
          {children}
        </Command>
      </DialogContent>
    </Dialog>
  );
};

const CommandInput = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Input>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Input>
>(({ className, ...props }, ref) => (
  <div className="flex items-center border-b px-3" cmdk-input-wrapper="">
    <Search className="mr-2 h-4 w-4 shrink-0 opacity-50" />
    <CommandPrimitive.Input
      ref={ref}
      className={cn(
        "flex h-11 w-full rounded-md bg-transparent py-3 text-sm outline-none placeholder:text-muted-foreground disabled:cursor-not-allowed disabled:opacity-50",
        className,
      )}
      {...props}
    />
  </div>
));

CommandInput.displayName = CommandPrimitive.Input.displayName;

const CommandList = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.List>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.List>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.List
    ref={ref}
    className={cn("max-h-[300px] overflow-y-auto overflow-x-hidden", className)}
    {...props}
  />
));

CommandList.displayName = CommandPrimitive.List.displayName;

const CommandEmpty = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Empty>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Empty>
>((props, ref) => <CommandPrimitive.Empty ref={ref} className="py-6 text-center text-sm" {...props} />);

CommandEmpty.displayName = CommandPrimitive.Empty.displayName;

const CommandGroup = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Group>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Group>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.Group
    ref={ref}
    className={cn(
      "overflow-hidden p-1 text-foreground [&_[cmdk-group-heading]]:px-2 [&_[cmdk-group-heading]]:py-1.5 [&_[cmdk-group-heading]]:text-xs [&_[cmdk-group-heading]]:font-medium [&_[cmdk-group-heading]]:text-muted-foreground",
      className,
    )}
    {...props}
  />
));

CommandGroup.displayName = CommandPrimitive.Group.displayName;

const CommandSeparator = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Separator>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Separator>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.Separator ref={ref} className={cn("-mx-1 h-px bg-border", className)} {...props} />
));
CommandSeparator.displayName = CommandPrimitive.Separator.displayName;

const CommandItem = React.forwardRef<
  React.ElementRef<typeof CommandPrimitive.Item>,
  React.ComponentPropsWithoutRef<typeof CommandPrimitive.Item>
>(({ className, ...props }, ref) => (
  <CommandPrimitive.Item
    ref={ref}
    className={cn(
      "relative flex cursor-default select-none items-center rounded-sm px-2 py-1.5 text-sm outline-none data-[disabled=true]:pointer-events-none data-[selected='true']:bg-accent data-[selected=true]:text-accent-foreground data-[disabled=true]:opacity-50",
      className,
    )}
    {...props}
  />
));

CommandItem.displayName = CommandPrimitive.Item.displayName;

const CommandShortcut = ({ className, ...props }: React.HTMLAttributes<HTMLSpanElement>) => {
  return <span className={cn("ml-auto text-xs tracking-widest text-muted-foreground", className)} {...props} />;
};
CommandShortcut.displayName = "CommandShortcut";

export {
  Command,
  CommandDialog,
  CommandInput,
  CommandList,
  CommandEmpty,
  CommandGroup,
  CommandItem,
  CommandShortcut,
  CommandSeparator,
};

import * as React from "react";

import { cn } from "@/lib/utils";

export interface TextareaProps extends React.TextareaHTMLAttributes<HTMLTextAreaElement> {}

const Textarea = React.forwardRef<HTMLTextAreaElement, TextareaProps>(({ className, ...props }, ref) => {
  return (
    <textarea
      className={cn(
        "flex min-h-[80px] w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50",
        className,
      )}
      ref={ref}
      {...props}
    />
  );
});
Textarea.displayName = "Textarea";

export { Textarea };

/**
 * Common validation utilities for form inputs
 */

// Phone validation: Indian mobile format (10 digits, starts with 6-9)
const PHONE_REGEX = /^[6-9]\d{9}$/;

// Email validation: standard RFC 5322 simplified
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// GST validation: 15 alphanumeric, specific format
// Format: 2 state digits + 10 PAN + 1 entity + 1 Z + 1 check
const GST_REGEX = /^[0-9]{2}[A-Z]{5}[0-9]{4}[A-Z]{1}[1-9A-Z]{1}Z[0-9A-Z]{1}$/;

// IFSC validation: 4 letters (bank) + 0 + 6 alphanumeric (branch)
const IFSC_REGEX = /^[A-Z]{4}0[A-Z0-9]{6}$/;

// PAN validation: 5 letters + 4 digits + 1 letter
const PAN_REGEX = /^[A-Z]{5}[0-9]{4}[A-Z]{1}$/;

// Aadhar validation: 12 digits
const AADHAR_REGEX = /^[2-9]\d{11}$/;

// UPI ID validation: username@provider
const UPI_REGEX = /^[\w.-]+@[\w]+$/;

export interface ValidationResult {
  valid: boolean;
  message?: string;
}

/**
 * Validate Indian phone number (10 digits starting with 6-9)
 */
export function validatePhone(phone: string, required = false): ValidationResult {
  const trimmed = phone.trim().replace(/[\s\-()]/g, "");
  
  if (!trimmed) {
    return required 
      ? { valid: false, message: "Phone number is required" }
      : { valid: true };
  }
  
  // Remove +91 or 91 prefix if present
  const normalized = trimmed.replace(/^(\+91|91)/, "");
  
  if (!PHONE_REGEX.test(normalized)) {
    return { 
      valid: false, 
      message: "Enter a valid 10-digit mobile number starting with 6-9" 
    };
  }
  
  return { valid: true };
}

/**
 * Validate email address
 */
export function validateEmail(email: string, required = false): ValidationResult {
  const trimmed = email.trim().toLowerCase();
  
  if (!trimmed) {
    return required 
      ? { valid: false, message: "Email is required" }
      : { valid: true };
  }
  
  if (!EMAIL_REGEX.test(trimmed)) {
    return { valid: false, message: "Enter a valid email address" };
  }
  
  return { valid: true };
}

/**
 * Validate GST number
 */
export function validateGST(gst: string, required = false): ValidationResult {
  const trimmed = gst.trim().toUpperCase();
  
  if (!trimmed) {
    return required 
      ? { valid: false, message: "GSTIN is required" }
      : { valid: true };
  }
  
  if (!GST_REGEX.test(trimmed)) {
    return { 
      valid: false, 
      message: "Enter a valid 15-character GSTIN (e.g., 29ABCDE1234F1Z5)" 
    };
  }
  
  return { valid: true };
}

/**
 * Validate IFSC code
 */
export function validateIFSC(ifsc: string, required = false): ValidationResult {
  const trimmed = ifsc.trim().toUpperCase();
  
  if (!trimmed) {
    return required 
      ? { valid: false, message: "IFSC code is required" }
      : { valid: true };
  }
  
  if (!IFSC_REGEX.test(trimmed)) {
    return { 
      valid: false, 
      message: "Enter a valid 11-character IFSC code (e.g., SBIN0001234)" 
    };
  }
  
  return { valid: true };
}

/**
 * Validate PAN number
 */
export function validatePAN(pan: string, required = false): ValidationResult {
  const trimmed = pan.trim().toUpperCase();
  
  if (!trimmed) {
    return required 
      ? { valid: false, message: "PAN is required" }
      : { valid: true };
  }
  
  if (!PAN_REGEX.test(trimmed)) {
    return { 
      valid: false, 
      message: "Enter a valid 10-character PAN (e.g., ABCDE1234F)" 
    };
  }
  
  return { valid: true };
}

/**
 * Validate Aadhar number
 */
export function validateAadhar(aadhar: string, required = false): ValidationResult {
  const trimmed = aadhar.trim().replace(/[\s\-]/g, "");
  
  if (!trimmed) {
    return required 
      ? { valid: false, message: "Aadhar number is required" }
      : { valid: true };
  }
  
  if (!AADHAR_REGEX.test(trimmed)) {
    return { 
      valid: false, 
      message: "Enter a valid 12-digit Aadhar number" 
    };
  }
  
  return { valid: true };
}

/**
 * Validate UPI ID
 */
export function validateUPI(upi: string, required = false): ValidationResult {
  const trimmed = upi.trim().toLowerCase();
  
  if (!trimmed) {
    return required 
      ? { valid: false, message: "UPI ID is required" }
      : { valid: true };
  }
  
  if (!UPI_REGEX.test(trimmed)) {
    return { 
      valid: false, 
      message: "Enter a valid UPI ID (e.g., name@upi)" 
    };
  }
  
  return { valid: true };
}

/**
 * Validate required text field
 */
export function validateRequired(value: string, fieldName: string): ValidationResult {
  if (!value.trim()) {
    return { valid: false, message: `${fieldName} is required` };
  }
  return { valid: true };
}

/**
 * Validate numeric amount (positive, optional min/max)
 */
export function validateAmount(
  value: number | string, 
  options: { required?: boolean; min?: number; max?: number; fieldName?: string } = {}
): ValidationResult {
  const { required = false, min = 0, max, fieldName = "Amount" } = options;
  const num = typeof value === "string" ? parseFloat(value) : value;
  
  if (isNaN(num) || value === "") {
    return required 
      ? { valid: false, message: `${fieldName} is required` }
      : { valid: true };
  }
  
  if (num < min) {
    return { valid: false, message: `${fieldName} must be at least ${min}` };
  }
  
  if (max !== undefined && num > max) {
    return { valid: false, message: `${fieldName} cannot exceed ${max}` };
  }
  
  return { valid: true };
}

/**
 * Normalize phone number (remove formatting, add/remove country code)
 */
export function normalizePhone(phone: string, includeCountryCode = false): string {
  const trimmed = phone.trim().replace(/[\s\-()]/g, "");
  const normalized = trimmed.replace(/^(\+91|91)/, "");
  
  if (!PHONE_REGEX.test(normalized)) {
    return phone.trim(); // Return as-is if invalid
  }
  
  return includeCountryCode ? `+91${normalized}` : normalized;
}

/**
 * Format phone number for display (XXX XXX XXXX)
 */
export function formatPhoneDisplay(phone: string): string {
  const normalized = normalizePhone(phone);
  if (normalized.length !== 10) return phone;
  return `${normalized.slice(0, 3)} ${normalized.slice(3, 6)} ${normalized.slice(6)}`;
}

import { useState } from "react";
// import { useNavigate } from "react-router-dom";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { useOnlineStatus } from "@/hooks/useOnlineStatus";
import { useRouteAccess } from "@/hooks/useRouteAccess";
import { addToQueue, queueFileUpload, fileToArrayBuffer } from "@/lib/offlineQueue";
import { getCurrentPosition, takePhoto } from "@/lib/capacitorUtils";
import { ArrowLeft, Check, ChevronRight, Loader2, MapPin, Store, User, UserPlus, Camera, WifiOff } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";

type Step = "type" | "customer" | "store" | "review";
type Mode = "customer" | "store" | "both";

export default function AddCustomerStore({ onClose }: { onClose: () => void }) {
  const { user, role } = useAuth();
  const { canAccessRoute, hasMatrixRestrictions, enabledRouteIds } = useRouteAccess(user?.id, role);
  const { isOnline } = useOnlineStatus();
  // const qc = useQueryClient();

  const [step, setStep] = useState<Step>("type");
  const [mode, setMode] = useState<Mode>("both");
  const [saving, setSaving] = useState(false);

  // Customer Data
  const [custId, setCustId] = useState(""); // For "store" mode (selecting existing)
  const [custName, setCustName] = useState("");
  const [custPhone, setCustPhone] = useState("");
  const [custEmail, setCustEmail] = useState("");
  // const [custPhoto, setCustPhoto] = useState("");
  const [custPhoto, setCustPhoto] = useState("");
  const [storePhoto, setStorePhoto] = useState("");
  // Track pending offline photos (stored as data URLs until sync)
  const [pendingCustPhoto, setPendingCustPhoto] = useState<string | null>(null);
  const [pendingStorePhoto, setPendingStorePhoto] = useState<string | null>(null);

  const handleTakePhoto = async (target: "customer" | "store") => {
    const dataUrl = await takePhoto();
    if (!dataUrl) return;

    const ext = "jpg";
    const path = `${target}s/${crypto.randomUUID()}.${ext}`; // customers/uuid.jpg or stores/uuid.jpg

    // If offline, queue for later upload
    if (!isOnline) {
      try {
        const res = await fetch(dataUrl);
        const blob = await res.blob();
        const fileData = await fileToArrayBuffer(blob);
        
        await queueFileUpload({
          id: `entity-photo-${target}-${Date.now()}`,
          type: target === "customer" ? "entity_photo" : "store_photo",
          fileName: `${target}_${Date.now()}.jpg`,
          bucket: "entity-photos",
          path,
          fileData,
          contentType: "image/jpeg",
          metadata: { target },
        });
        
        // Store locally to show preview (data URL)
        if (target === "customer") {
          setPendingCustPhoto(dataUrl);
          setCustPhoto(path); // Store path for later reference
        } else {
          setPendingStorePhoto(dataUrl);
          setStorePhoto(path);
        }
        
        toast.success("Photo saved for upload when online", {
          icon: <WifiOff className="h-4 w-4" />,
        });
      } catch (err: any) {
        toast.error("Failed to queue photo: " + err.message);
      }
      return;
    }

    // Online: Upload to Supabase immediately
    try {
        const res = await fetch(dataUrl);
        const blob = await res.blob();

        const { error } = await supabase.storage.from("entity-photos").upload(path, blob);
        if (error) throw error;

        const { data: { publicUrl } } = supabase.storage.from("entity-photos").getPublicUrl(path);
        
        if (target === "customer") {
          setCustPhoto(publicUrl);
          setPendingCustPhoto(null);
        } else {
          setStorePhoto(publicUrl);
          setPendingStorePhoto(null);
        }
        
        toast.success("Photo uploaded");
    } catch (err: any) {
        toast.error("Photo upload failed: " + err.message);
    }
  };

  // Store Data
  const [storeName, setStoreName] = useState("");
  // const [storePhone, setStorePhone] = useState("");
  const storePhone = ""; // Use cust phone by default or add input later
  const [storeTypeId, setStoreTypeId] = useState("");
  const [routeId, setRouteId] = useState("");
  const [address, setAddress] = useState("");
  const [lat, setLat] = useState<number | null>(null);
  const [lng, setLng] = useState<number | null>(null);
  const [locating, setLocating] = useState(false);

  // Fetch meta data
  const { data: storeTypes } = useQuery({
    queryKey: ["store-types", user?.id, hasMatrixRestrictions],
    queryFn: async () => {
      let q = supabase.from("store_types").select("*").eq("is_active", true);
      const { data } = await q;
      let types = data || [];

      if (hasMatrixRestrictions && enabledRouteIds.size > 0) {
        // If restricted, only show types that exist on allowed routes?
        // Actually, store_types are linked to routes. Routes are linked to store_types.
        // Let's filter available types based on accessible routes if we want strictness.
        // But usually permissions are handled by restricting routes.
        // For now, let's keep all store types unless we want to do heavy filtering.
        // But let's at least filter routes.
      }
      return types;
    },
    enabled: step === "store",
  });

  const { data: routes } = useQuery({
    queryKey: ["routes-list", storeTypeId, user?.id],
    queryFn: async () => {
      let q = supabase.from("routes").select("*").eq("is_active", true);
      if (storeTypeId) q = q.eq("store_type_id", storeTypeId);
      const { data } = await q;
      let fetchedRoutes = data || [];
      
      // Filter by access
      if (hasMatrixRestrictions) {
        fetchedRoutes = fetchedRoutes.filter(r => canAccessRoute(r.id));
      }
      return fetchedRoutes;
    },
    enabled: step === "store",
  });

  const { data: customers } = useQuery({
    queryKey: ["customers-list-simple"],
    queryFn: async () => {
      const { data } = await supabase.from("customers").select("id, name, phone, display_id").order("name");
      return data || [];
    },
    enabled: step === "customer" && mode === "store",
  });

  const handleNext = () => {
    if (step === "type") {
      if (mode === "store") setStep("customer"); // Select customer
      else setStep("customer"); // Create customer
    } else if (step === "customer") {
      if (mode === "customer") setStep("review");
      else setStep("store");
    } else if (step === "store") {
      setStep("review");
    }
  };

  const captureLocation = async () => {
    setLocating(true);
    const pos = await getCurrentPosition();
    if (pos) {
      setLat(pos.lat);
      setLng(pos.lng);
      // Optional: Reverse geocode could go here, but omitted for speed/simplicity or added later
      toast.success("Location captured");
    } else {
      toast.error("Could not get location");
    }
    setLocating(false);
  };

  const handleSubmit = async () => {
    if (mode !== "customer" && !storeName) return toast.error("Store name required");
    if (mode !== "store" && !custName) return toast.error("Customer name required");
    if (mode !== "store" && (!custPhone || custPhone.length < 10)) return toast.error("Valid customer phone required");

    setSaving(true);

    // Duplicate check if online
    if (isOnline && (mode === "store" || mode === "both")) {
        try {
            const warnings: string[] = [];
            const nameTrimmed = storeName.trim();
            if (nameTrimmed) {
                const { data: nameMatches } = await supabase.from("stores").select("name").eq("is_active", true).ilike("name", nameTrimmed);
                if (nameMatches && nameMatches.length > 0) warnings.push(`A store named "${nameTrimmed}" already exists.`);
            }
            if (lat && lng) {
                const { data: closeStores } = await supabase.rpc("check_store_proximity", { p_lat: lat, p_lng: lng, p_radius_m: 50 });
                if (closeStores && closeStores.length > 0) warnings.push(`There is already a store within 50 meters of this location.`);
            }
            if (warnings.length > 0) {
                const proceed = window.confirm(`WARNING:\n\n${warnings.join('\n')}\n\nDo you still want to create this store?`);
                if (!proceed) {
                    setSaving(false);
                    return;
                }
            }
        } catch (err) {
            console.error("Dupe check failed", err);
        }
    }

    try {
      await processSubmission();

      toast.success("Saved successfully");
      onClose();
    } catch (err: any) {
      toast.error(err.message || "Failed to save");
    } finally {
      setSaving(false);
    }
  };

  const processSubmission = async () => {
      const now = new Date().toISOString();
      let finalCustId = custId;

      // --- CUSTOMER ---
      if (mode === "customer" || mode === "both") {
          const custPayload = {
              name: custName,
              phone: custPhone,
              email: custEmail || null,
              photo_url: custPhoto || null,
              created_at: now,
          };

          if (isOnline) {
               const { data: did } = await supabase.rpc("generate_display_id", { prefix: "CUST", seq_name: "cust_display_seq" });
               const { data: newC, error } = await supabase.from("customers").insert({ ...custPayload, display_id: did }).select("id").single();
               if (error) throw error;
               finalCustId = newC.id;
          } else {
               finalCustId = crypto.randomUUID();
               await addToQueue({
                   id: crypto.randomUUID(),
                   type: "customer",
                   payload: { customerData: { ...custPayload, id: finalCustId } },
                   createdAt: now
               });
          }
      }

      // --- STORE ---
      if (mode === "store" || mode === "both") {
          if (!finalCustId) throw new Error("No customer linked");

          const storePayload = {
              name: storeName,
              customer_id: finalCustId,
              store_type_id: storeTypeId,
              route_id: routeId || null,
              phone: storePhone || custPhone, // Fallback
              address: address || null,
              lat: lat,
              lng: lng,
              created_at: now,
              is_active: true,
          };

          if (isOnline) {
               const { data: did } = await supabase.rpc("generate_display_id", { prefix: "STR", seq_name: "str_display_seq" });
               const { error } = await supabase.from("stores").insert({ ...storePayload, display_id: did });
               if (error) throw error;
          } else {
               await addToQueue({
                   id: crypto.randomUUID(),
                   type: "store",
                   payload: { storeData: { ...storePayload, id: crypto.randomUUID() }, storePricing: [] },
                   createdAt: now
               });
          }
      }
  };

  return (
    <div className="fixed inset-0 bg-slate-50 dark:bg-slate-950 z-50 flex flex-col pt-[env(safe-area-inset-top)]">
        {/* Header */}
        <div className="h-14 flex items-center justify-between px-4 bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800">
            <button onClick={onClose} className="p-2 -ml-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800">
                <ArrowLeft className="h-5 w-5 text-slate-600 dark:text-slate-300" />
            </button>
            <h1 className="text-base font-bold text-slate-800 dark:text-white">
                {step === "type" ? "Add New" : step === "review" ? "Review" : step === "customer" ? "Customer Details" : "Store Details"}
            </h1>
            <div className="w-9" />
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-4 pb-20">
            {step === "type" && (
                <div className="grid gap-4">
                    <button 
                        onClick={() => { setMode("both"); setStep("customer"); }}
                        className="p-4 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex items-center gap-4 text-left active:scale-[0.98] transition-transform"
                    >
                        <div className="h-12 w-12 rounded-full bg-blue-100 dark:bg-blue-900/40 flex items-center justify-center">
                            <UserPlus className="h-6 w-6 text-blue-600 dark:text-blue-400" />
                        </div>
                        <div>
                            <h3 className="font-bold text-slate-800 dark:text-white">New Customer + Store</h3>
