}

interface WorkerBalance {
  id: string;
  user_id?: string;
  worker_id?: string;
  total_earned: number;
  total_paid: number;
  outstanding_balance: number;
  worker?: { name: string; display_id: string };
  profile?: { full_name: string };
}

// Helper function to calculate pay based on hours worked and shift rates
function calculateShiftPay(hoursWorked: number, shiftRates: any[]): { rate: number; amount: number } {
  if (shiftRates.length === 0) return { rate: 0, amount: 0 };
  
  // Find the closest matching shift rate
  let closestShift = shiftRates[0];
  let minDiff = Math.abs(hoursWorked - shiftRates[0].duration_hours);
  
  for (const shift of shiftRates) {
    const diff = Math.abs(hoursWorked - shift.duration_hours);
    if (diff < minDiff) {
      minDiff = diff;
      closestShift = shift;
    }
  }
  
  // Calculate proportional pay based on closest shift
  // Guard against division by zero
  if (!closestShift.duration_hours || closestShift.duration_hours <= 0) {
    return { rate: 0, amount: 0 };
  }
  
  const proportionalAmount = (hoursWorked / closestShift.duration_hours) * closestShift.rate_amount;
  
  return {
    rate: closestShift.rate_amount / closestShift.duration_hours, // hourly rate for reference
    amount: Math.round(proportionalAmount * 100) / 100 // round to 2 decimals
  };
}

export default function Attendance() {
  const { user } = useAuth();
  const qc = useQueryClient();
  const [activeTab, setActiveTab] = useState("records");
  
  // Workers state
  const [showWorkerDialog, setShowWorkerDialog] = useState(false);
  const [editingWorker, setEditingWorker] = useState<Worker | null>(null);
  const [workerName, setWorkerName] = useState("");
  const [workerPhone, setWorkerPhone] = useState("");
  const [deletingWorkerId, setDeletingWorkerId] = useState<string | null>(null);
  
  // Shift rates state
  const [showShiftRatesDialog, setShowShiftRatesDialog] = useState(false);
  const [editingShiftRate, setEditingShiftRate] = useState<any>(null);
  const [shiftRateName, setShiftRateName] = useState("");
  const [shiftRateDuration, setShiftRateDuration] = useState("");
  const [shiftRateAmount, setShiftRateAmount] = useState("");
  
  // Attendance record state
  const [showAttendanceDialog, setShowAttendanceDialog] = useState(false);
  const [attendanceDate, setAttendanceDate] = useState(format(new Date(), "yyyy-MM-dd"));
  const [factoryStartTime, setFactoryStartTime] = useState("09:00");
  const [factoryEndTime, setFactoryEndTime] = useState("18:00");
  const [attendanceNotes, setAttendanceNotes] = useState("");
  const [attendanceEntries, setAttendanceEntries] = useState<{
    person_type: "staff" | "worker";
    person_id: string;
    person_name: string;
    is_present: boolean;
    check_in: string;
    check_out: string;
  }[]>([]);
  
  // Payment state
  const [showPaymentDialog, setShowPaymentDialog] = useState(false);
  const [paymentPersonType, setPaymentPersonType] = useState<"staff" | "worker">("worker");
  const [paymentPersonId, setPaymentPersonId] = useState("");
  const [paymentAmount, setPaymentAmount] = useState("");
  const [paymentMethod, setPaymentMethod] = useState("cash");
  const [paymentNotes, setPaymentNotes] = useState("");
  
  // Edit attendance state
  const [editingRecord, setEditingRecord] = useState<AttendanceRecord | null>(null);
  const [showEditEntriesDialog, setShowEditEntriesDialog] = useState(false);
  const [editEntries, setEditEntries] = useState<AttendanceEntry[]>([]);
  
  const [saving, setSaving] = useState(false);

  // Queries
  const { data: shiftRates = [] } = useQuery({
    queryKey: ["shift-rates"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("shift_rates")
        .select("*")
        .eq("is_active", true)
        .order("duration_hours");
      if (error) throw error;
      return data;
    },
  });

  const { data: workers = [], isLoading: loadingWorkers } = useQuery({
    queryKey: ["workers"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("workers")
        .select("*")
        .order("name");
      if (error) throw error;
      return data as Worker[];
    },
  });

  const { data: staffUsers = [] } = useQuery({
    queryKey: ["staff-for-attendance"],
    queryFn: async () => {
      // Get all staff (agents, marketers, pos) - exclude managers and customers
      const { data, error } = await supabase
        .from("user_roles")
        .select("user_id, role")
        .not("role", "in", "(manager,super_admin,customer)");
      if (error) throw error;
      
      if (!data || data.length === 0) return [];
      
      // Get profiles for these users
      const userIds = data.map(d => d.user_id);
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, full_name, hourly_rate")
        .in("id", userIds);
      
      // Merge data
      return data.map(ur => ({
        ...ur,
        profiles: profiles?.find(p => p.id === ur.user_id) || { full_name: "Unknown", hourly_rate: 0 }
      }));
    },
  });

  const PAGE_SIZE = 100;
  const [loadedPages, setLoadedPages] = useState(1);

  const { data: attendanceRecords = [], isLoading: loadingRecords, isFetching: fetchingRecords } = useQuery({
    queryKey: ["attendance-records", loadedPages],
    queryFn: async () => {
      let query = supabase
        .from("attendance_records")
        .select(`
          *,
          attendance_entries(count)
        `)
        .order("attendance_date", { ascending: false });
        
      query = query.range(0, loadedPages * PAGE_SIZE - 1);
      const { data, error } = await query;
      if (error) throw error;
      return data.map(r => ({
        ...r,
        entries_count: r.attendance_entries?.[0]?.count || 0
      })) as AttendanceRecord[];
    },
  });

  const hasMoreRecords = attendanceRecords.length >= loadedPages * PAGE_SIZE;

  const { data: balances = [], isLoading: loadingBalances } = useQuery({
    queryKey: ["worker-balances"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("worker_balances")
        .select(`
          *,
          workers(name, display_id)
        `)
        .order("outstanding_balance", { ascending: false });
      if (error) throw error;
      
      if (!data || data.length === 0) return [];
      
      // Get profiles for users with user_id
      const userIds = data.filter(d => d.user_id).map(d => d.user_id!);
      let profilesMap: Record<string, { full_name: string }> = {};
      
      if (userIds.length > 0) {
        const { data: profiles } = await supabase
          .from("profiles")
          .select("id, full_name")
          .in("id", userIds);
        
        profiles?.forEach(p => { profilesMap[p.id] = { full_name: p.full_name }; });
      }
      
      return data.map(b => ({
        ...b,
        profiles: b.user_id ? profilesMap[b.user_id] : null
      })) as WorkerBalance[];
    },
  });

  // Worker mutations
  const resetWorkerForm = () => {
    setEditingWorker(null);
    setWorkerName("");
    setWorkerPhone("");
  };

  const saveWorkerMutation = useMutation({
    mutationFn: async () => {
      if (editingWorker) {
        const { error } = await supabase
          .from("workers")
          .update({
            name: workerName,
            phone: workerPhone || null,
            updated_at: new Date().toISOString(),
          })
          .eq("id", editingWorker.id);
        if (error) throw error;
      } else {
        const { data: idData } = await supabase.rpc("generate_display_id", {
          prefix: "WRK",
          seq_name: "workers_display_id_seq"
        });
        
        const { error } = await supabase.from("workers").insert({
          display_id: idData,
          name: workerName,
          phone: workerPhone || null,
        });
        if (error) throw error;
      }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["workers"] });
      toast.success(editingWorker ? "Worker updated" : "Worker added");
      setShowWorkerDialog(false);
      resetWorkerForm();
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  const deleteWorkerMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("workers").update({ is_active: false }).eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["workers"] });
      toast.success("Worker deactivated");
      setDeletingWorkerId(null);
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  // Shift rates mutations
  const resetShiftRateForm = () => {
    setEditingShiftRate(null);
    setShiftRateName("");
    setShiftRateDuration("");
    setShiftRateAmount("");
  };

  const saveShiftRateMutation = useMutation({
    mutationFn: async () => {
      if (editingShiftRate) {
        const { error } = await supabase
          .from("shift_rates")
          .update({
            shift_name: shiftRateName,
            duration_hours: parseFloat(shiftRateDuration),
            rate_amount: parseFloat(shiftRateAmount),
            updated_at: new Date().toISOString(),
          })
          .eq("id", editingShiftRate.id);
        if (error) throw error;
      } else {
        const { data: idData } = await supabase.rpc("generate_display_id", {
          prefix: "SR",
          seq_name: "shift_rates_display_id_seq"
        });
        
        const { error } = await supabase.from("shift_rates").insert({
          display_id: idData,
          shift_name: shiftRateName,
          duration_hours: parseFloat(shiftRateDuration),
          rate_amount: parseFloat(shiftRateAmount),
          created_by: user?.id,
        });
        if (error) throw error;
      }
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["shift-rates"] });
      toast.success(editingShiftRate ? "Shift rate updated" : "Shift rate added");
      resetShiftRateForm();
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  const deleteShiftRateMutation = useMutation({
    mutationFn: async (id: string) => {
      const { error } = await supabase.from("shift_rates").update({ is_active: false }).eq("id", id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["shift-rates"] });
      toast.success("Shift rate deleted");
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  // Attendance mutations
  const initAttendanceEntries = () => {
    const entries: typeof attendanceEntries = [];
    
    // Add all active workers
    workers.filter(w => w.is_active).forEach(w => {
      entries.push({
        person_type: "worker",
        person_id: w.id,
        person_name: w.name,
        is_present: true,
        check_in: factoryStartTime,
        check_out: factoryEndTime,
      });
    });
    
    // Add all staff (non-manager, non-admin)
    staffUsers.forEach((s: any) => {
      entries.push({
        person_type: "staff",
        person_id: s.user_id,
        person_name: s.profiles?.full_name || "Unknown",
        is_present: true,
        check_in: factoryStartTime,
        check_out: factoryEndTime,
      });
    });
    
    setAttendanceEntries(entries);
  };

  const saveAttendanceMutation = useMutation({
    mutationFn: async () => {
      // Generate display ID
      const { data: idData } = await supabase.rpc("generate_display_id", {
        prefix: "ATT",
        seq_name: "attendance_display_id_seq"
      });

      // Create attendance record
      const { data: record, error: recordError } = await supabase
        .from("attendance_records")
        .insert({
          display_id: idData,
          attendance_date: attendanceDate,
          recorded_by: user!.id,
          factory_start_time: factoryStartTime,
          factory_end_time: factoryEndTime,
          notes: attendanceNotes || null,
        })
        .select()
        .single();

      if (recordError) throw recordError;

      // Create attendance entries for present people
      const entries = attendanceEntries
        .filter(e => e.is_present)
        .map(e => {
          // Calculate hours worked
          const checkIn = new Date(`2000-01-01T${e.check_in}:00`);
          const checkOut = new Date(`2000-01-01T${e.check_out}:00`);
          const hoursWorked = (checkOut.getTime() - checkIn.getTime()) / (1000 * 60 * 60);
          
          // Calculate pay based on shift rates
          const { rate, amount } = calculateShiftPay(hoursWorked, shiftRates);
          
          return {
            attendance_id: record.id,
            user_id: e.person_type === "staff" ? e.person_id : null,
            worker_id: e.person_type === "worker" ? e.person_id : null,
            is_present: true,
            check_in_time: e.check_in,
            check_out_time: e.check_out,
            hourly_rate: rate, // Store calculated hourly rate for reference
          };
        });

      if (entries.length > 0) {
        const { error: entriesError } = await supabase
          .from("attendance_entries")
          .insert(entries);
        if (entriesError) throw entriesError;
      }

      return record;
    },
    onSuccess: (record) => {
      qc.invalidateQueries({ queryKey: ["attendance-records"] });
      qc.invalidateQueries({ queryKey: ["worker-balances"] });
      toast.success(`Attendance recorded: ${record.display_id}`);
      logActivity(user!.id, `Recorded attendance for ${attendanceDate}`, "attendance");
      setShowAttendanceDialog(false);
      setAttendanceEntries([]);
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  // Payment mutation
  const savePaymentMutation = useMutation({
    mutationFn: async () => {
      const { data: idData } = await supabase.rpc("generate_display_id", {
        prefix: "WPY",
        seq_name: "worker_payments_display_id_seq"
      });

      const { error } = await supabase.from("worker_payments").insert({
        display_id: idData,
        user_id: paymentPersonType === "staff" ? paymentPersonId : null,
        worker_id: paymentPersonType === "worker" ? paymentPersonId : null,
        amount: parseFloat(paymentAmount),
        payment_method: paymentMethod,
        notes: paymentNotes || null,
        created_by: user!.id,
      });
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["worker-balances"] });
      toast.success("Payment recorded");
      setShowPaymentDialog(false);
      setPaymentPersonId("");
      setPaymentAmount("");
      setPaymentNotes("");
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  // Edit entries for a record
  const loadEntriesForEdit = async (record: AttendanceRecord) => {
    const { data, error } = await supabase
      .from("attendance_entries")
      .select(`
        *,
        workers(name, display_id)
      `)
      .eq("attendance_id", record.id);
    
    if (error) {
      toast.error("Failed to load entries");
      return;
    }
    
    if (!data || data.length === 0) {
      setEditingRecord(record);
      setEditEntries([]);
      setShowEditEntriesDialog(true);
      return;
    }
    
    // Get profiles for users
    const userIds = data.filter(d => d.user_id).map(d => d.user_id!);
    let profilesMap: Record<string, { full_name: string }> = {};
    
    if (userIds.length > 0) {
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, full_name")
        .in("id", userIds);
      
      profiles?.forEach(p => { profilesMap[p.id] = { full_name: p.full_name }; });
    }
    
    const entriesWithProfiles = data.map(e => ({
      ...e,
      profiles: e.user_id ? profilesMap[e.user_id] : null
    }));
    
    setEditingRecord(record);
    setEditEntries(entriesWithProfiles as AttendanceEntry[]);
    setShowEditEntriesDialog(true);
  };

  const updateEntryMutation = useMutation({
    mutationFn: async (entry: AttendanceEntry) => {
      const { error } = await supabase
        .from("attendance_entries")
        .update({
          check_in_time: entry.check_in_time,
          check_out_time: entry.check_out_time,
          hourly_rate: entry.hourly_rate,
          adjustment_amount: entry.adjustment_amount,
          adjustment_reason: entry.adjustment_reason,
          notes: entry.notes,
          updated_at: new Date().toISOString(),
        })
        .eq("id", entry.id);
      if (error) throw error;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["attendance-records"] });
      qc.invalidateQueries({ queryKey: ["worker-balances"] });
      toast.success("Entry updated");
    },
    onError: (e: Error) => toast.error(`Failed: ${e.message}`),
  });

  const handleEditWorker = (w: Worker) => {
    setEditingWorker(w);
    setWorkerName(w.name);
    setWorkerPhone(w.phone || "");
    setShowWorkerDialog(true);
  };

  const calculateHours = (checkIn: string, checkOut: string) => {
    if (!checkIn || !checkOut) return 0;
    const [inH, inM] = checkIn.split(":").map(Number);
    const [outH, outM] = checkOut.split(":").map(Number);
    return Math.max(0, (outH * 60 + outM - inH * 60 - inM) / 60);
  };

  const updateEntryTime = (index: number, field: "check_in" | "check_out", value: string) => {
    const updated = [...attendanceEntries];
    updated[index] = { ...updated[index], [field]: value };
    setAttendanceEntries(updated);
  };

  const totalOwed = balances.reduce((sum, b) => sum + Math.max(0, Number(b.outstanding_balance)), 0);
  const totalAdvance = balances.reduce((sum, b) => sum + Math.max(0, -Number(b.outstanding_balance)), 0);

  if (loadingRecords && loadingWorkers) {
    return <TableSkeleton columns={6} />;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Attendance"
        subtitle="Track daily attendance and calculate wages"
        primaryAction={{
          label: "Record Attendance",
          icon: Calendar,
          onClick: () => {
            initAttendanceEntries();
            setShowAttendanceDialog(true);
          },
        }}
        actions={[
          { label: "Add Worker", onClick: () => { resetWorkerForm(); setShowWorkerDialog(true); }, priority: 1 },
          { label: "Make Payment", onClick: () => setShowPaymentDialog(true), priority: 2 },
          { label: "Shift Rates", onClick: () => setShowShiftRatesDialog(true), priority: 3 },
        ]}
      />

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Total Workers</p>
                <p className="text-2xl font-bold">{workers.filter(w => w.is_active).length}</p>
              </div>
              <Users className="h-8 w-8 text-blue-500 opacity-80" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Staff Members</p>
                <p className="text-2xl font-bold">{staffUsers.length}</p>
              </div>
              <UserPlus className="h-8 w-8 text-purple-500 opacity-80" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Company Owes</p>
                <p className="text-2xl font-bold text-red-600">₹{totalOwed.toLocaleString()}</p>
              </div>
              <ArrowUpRight className="h-8 w-8 text-red-500 opacity-80" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-muted-foreground">Advance Paid</p>
                <p className="text-2xl font-bold text-green-600">₹{totalAdvance.toLocaleString()}</p>
              </div>
              <ArrowDownRight className="h-8 w-8 text-green-500 opacity-80" />
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Tabs */}
      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="grid w-full grid-cols-3 lg:w-auto lg:inline-grid">
          <TabsTrigger value="records">Attendance Records</TabsTrigger>
          <TabsTrigger value="workers">Workers</TabsTrigger>
          <TabsTrigger value="balances">Balances</TabsTrigger>
        </TabsList>

        {/* Attendance Records Tab */}
        <TabsContent value="records" className="mt-4">
          <Card>
            <CardHeader>
              <CardTitle>Attendance History</CardTitle>
              <CardDescription>View and edit past attendance records</CardDescription>
            </CardHeader>
            <CardContent>
              <DataTable
                columns={[
                  { header: "ID", accessor: "display_id", className: "font-mono text-xs" },
                  { header: "Date", accessor: (r: AttendanceRecord) => format(parseISO(r.attendance_date), "dd MMM yyyy") },
                  { header: "Hours", accessor: (r: AttendanceRecord) => `${r.factory_start_time} - ${r.factory_end_time}` },
                  { header: "Entries", accessor: (r: AttendanceRecord) => r.entries_count || 0, className: "text-center" },
                  {
                    header: "Status",
                    accessor: (r: AttendanceRecord) => (
                      <StatusBadge status={r.is_finalized ? "active" : "pending"} label={r.is_finalized ? "Finalized" : "Draft"} />
                    ),
                  },
                  {
                    header: "Actions",
                    accessor: (r: AttendanceRecord) => (
                      <Button variant="ghost" size="sm" onClick={() => loadEntriesForEdit(r)}>
                        <Pencil className="h-4 w-4 mr-1" />
                        Edit
                      </Button>
                    ),
                  },
                ]}
                data={attendanceRecords}
                searchKey="display_id"
                searchPlaceholder="Search by ID..."
                emptyMessage="No attendance records yet"
                renderMobileCard={(r: AttendanceRecord) => (
                  <div className="entity-card-mobile flex-col !items-stretch">
                    <div className="flex items-start justify-between">
                      <div className="min-w-0">
                        <p className="entity-card-subtitle">{r.display_id}</p>
                        <p className="font-semibold">{format(parseISO(r.attendance_date), "dd MMM yyyy")}</p>
                        <p className="text-sm text-muted-foreground">{r.factory_start_time} - {r.factory_end_time}</p>
                      </div>
                      <StatusBadge status={r.is_finalized ? "active" : "pending"} label={r.is_finalized ? "Final" : "Draft"} />
                    </div>
                    <div className="flex items-center justify-between mt-2 pt-2 border-t">
                      <span className="text-sm">{r.entries_count} entries</span>
                      <Button variant="outline" size="sm" onClick={() => loadEntriesForEdit(r)}>
                        <Pencil className="h-4 w-4 mr-1" />
                        Edit
                      </Button>
                    </div>
                  </div>
                )}
              />
              {hasMoreRecords && (
                <div className="flex justify-center pt-4">
                  <Button variant="outline" size="sm" onClick={() => setLoadedPages((p) => p + 1)} disabled={fetchingRecords} className="gap-1.5">
                    {fetchingRecords ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : null}
                    Load more
                  </Button>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* Workers Tab */}
        <TabsContent value="workers" className="mt-4">
          <Card>
            <CardHeader>
              <CardTitle>Workers List</CardTitle>
              <CardDescription>Manage non-staff workers</CardDescription>
            </CardHeader>
            <CardContent>
              <DataTable
                columns={[
                  { header: "ID", accessor: "display_id", className: "font-mono text-xs" },
                  { header: "Name", accessor: "name", className: "font-medium" },
                  { header: "Phone", accessor: (w: Worker) => w.phone || "—" },
                  { header: "Hourly Rate", accessor: (w: Worker) => `₹${w.hourly_rate}/hr` },
                  {
                    header: "Status",
                    accessor: (w: Worker) => (
                      <StatusBadge status={w.is_active ? "active" : "inactive"} />
                    ),
                  },
                  {
                    header: "Actions",
                    accessor: (w: Worker) => (
                      <div className="flex gap-1">
                        <Button variant="ghost" size="icon" className="h-8 w-8" onClick={() => handleEditWorker(w)}>
                          <Pencil className="h-4 w-4" />
                        </Button>
                        <Button variant="ghost" size="icon" className="h-8 w-8 text-destructive" onClick={() => setDeletingWorkerId(w.id)}>
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    ),
                  },
                ]}
                data={workers}
                searchKey="name"
                searchPlaceholder="Search workers..."
                emptyMessage="No workers added yet"
                renderMobileCard={(w: Worker) => (
                  <div className="entity-card-mobile flex-col !items-stretch">
                    <div className="flex items-start justify-between">
                      <div className="min-w-0">
                        <p className="entity-card-subtitle">{w.display_id}</p>
                        <p className="font-semibold">{w.name}</p>
                        <p className="text-sm text-muted-foreground">{w.phone || "No phone"}</p>
                      </div>
                      <StatusBadge status={w.is_active ? "active" : "inactive"} />
                    </div>
                    <div className="flex items-center justify-between mt-2 pt-2 border-t">
                      <span className="font-medium">₹{w.hourly_rate}/hr</span>
                      <div className="flex gap-2">
                        <Button variant="outline" size="sm" onClick={() => handleEditWorker(w)}>
                          <Pencil className="h-4 w-4" />
                        </Button>
                        <Button variant="outline" size="sm" className="text-destructive" onClick={() => setDeletingWorkerId(w.id)}>
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  </div>
                )}
              />
            </CardContent>
          </Card>
        </TabsContent>

        {/* Balances Tab */}
        <TabsContent value="balances" className="mt-4">
          <Card>
            <CardHeader>
              <CardTitle>Outstanding Balances</CardTitle>
              <CardDescription>Track what company owes to workers/staff</CardDescription>
            </CardHeader>
            <CardContent>
              <DataTable
                columns={[
                  { 
                    header: "Person", 
                    accessor: (b: WorkerBalance) => b.workers?.name || (b as any).profiles?.full_name || "Unknown",
                    className: "font-medium"
                  },
                  { header: "Type", accessor: (b: WorkerBalance) => b.worker_id ? "Worker" : "Staff", className: "text-sm" },
                  { header: "Total Earned", accessor: (b: WorkerBalance) => `₹${Number(b.total_earned).toLocaleString()}` },
                  { header: "Total Paid", accessor: (b: WorkerBalance) => `₹${Number(b.total_paid).toLocaleString()}` },
                  { 
                    header: "Balance", 
                    accessor: (b: WorkerBalance) => {
                      const bal = Number(b.outstanding_balance);
                      return (
                        <span className={bal > 0 ? "text-red-600 font-semibold" : bal < 0 ? "text-green-600 font-semibold" : ""}>
                          ₹{Math.abs(bal).toLocaleString()}
                          {bal > 0 ? " (owed)" : bal < 0 ? " (advance)" : ""}
                        </span>
                      );
                    }
                  },
                ]}
                data={balances}
                searchKey="workers.name"
                searchPlaceholder="Search..."
                emptyMessage="No balance records yet"
                renderMobileCard={(b: WorkerBalance) => (
                  <div className="entity-card-mobile flex-col !items-stretch">
                    <div className="flex items-start justify-between">
                      <div className="min-w-0">
                        <p className="font-semibold">{b.workers?.name || (b as any).profiles?.full_name || "Unknown"}</p>
                        <p className="text-xs text-muted-foreground">{b.worker_id ? "Worker" : "Staff"}</p>
                      </div>
                      {Number(b.outstanding_balance) > 0 ? (
                        <span className="px-2 py-1 rounded-full text-xs bg-red-500/10 text-red-600 font-medium">Owed</span>
                      ) : Number(b.outstanding_balance) < 0 ? (
                        <span className="px-2 py-1 rounded-full text-xs bg-green-500/10 text-green-600 font-medium">Advance</span>
                      ) : null}
                    </div>
                    <div className="grid grid-cols-3 gap-2 mt-2 pt-2 border-t text-sm">
                      <div>
                        <p className="text-muted-foreground text-xs">Earned</p>
                        <p className="font-medium">₹{Number(b.total_earned).toLocaleString()}</p>
                      </div>
                      <div>
                        <p className="text-muted-foreground text-xs">Paid</p>
                        <p className="font-medium">₹{Number(b.total_paid).toLocaleString()}</p>
                      </div>
                      <div>
                        <p className="text-muted-foreground text-xs">Balance</p>
                        <p className={`font-bold ${Number(b.outstanding_balance) > 0 ? "text-red-600" : Number(b.outstanding_balance) < 0 ? "text-green-600" : ""}`}>
                          ₹{Math.abs(Number(b.outstanding_balance)).toLocaleString()}
                        </p>
                      </div>
                    </div>
                  </div>
                )}
              />
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Add/Edit Worker Dialog */}
      <Dialog open={showWorkerDialog} onOpenChange={(open) => { setShowWorkerDialog(open); if (!open) resetWorkerForm(); }}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>{editingWorker ? "Edit Worker" : "Add Worker"}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label>Name *</Label>
              <Input value={workerName} onChange={(e) => setWorkerName(e.target.value)} placeholder="Worker name" />
            </div>
            <div className="space-y-2">
              <Label>Phone</Label>
              <Input value={workerPhone} onChange={(e) => setWorkerPhone(e.target.value)} placeholder="Phone number" />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowWorkerDialog(false)}>Cancel</Button>
            <Button onClick={() => saveWorkerMutation.mutate()} disabled={!workerName.trim() || saveWorkerMutation.isPending}>
              {saveWorkerMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {editingWorker ? "Update" : "Add"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Record Attendance Dialog */}
      <Dialog open={showAttendanceDialog} onOpenChange={setShowAttendanceDialog}>
        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Record Attendance</DialogTitle>
          </DialogHeader>
          <div className="space-y-6 py-4">
            {/* Date and Time Settings */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="space-y-2">
                <Label>Date *</Label>
                <Input type="date" value={attendanceDate} onChange={(e) => setAttendanceDate(e.target.value)} />
              </div>
              <div className="space-y-2">
                <Label>Factory Start Time</Label>
                <Input 
                  type="time" 
                  value={factoryStartTime} 
                  onChange={(e) => {
                    setFactoryStartTime(e.target.value);
                    // Update all entries to use new start time
                    setAttendanceEntries(prev => prev.map(entry => ({ ...entry, check_in: e.target.value })));
                  }} 
                />
              </div>
              <div className="space-y-2">
                <Label>Factory End Time</Label>
                <Input 
                  type="time" 
                  value={factoryEndTime} 
                  onChange={(e) => {
                    setFactoryEndTime(e.target.value);
                    // Update all entries to use new end time
                    setAttendanceEntries(prev => prev.map(entry => ({ ...entry, check_out: e.target.value })));
                  }} 
                />
              </div>
            </div>

            {/* Attendance Entries */}
            <div>
              <Label className="mb-3 block">Attendance ({attendanceEntries.filter(e => e.is_present).length} present)</Label>
              <div className="border rounded-lg divide-y">
                {attendanceEntries.map((entry, index) => {
                  const hours = calculateHours(entry.check_in, entry.check_out);
                  const amount = hours * entry.hourly_rate;
                  
                  return (
                    <div key={`${entry.person_type}-${entry.person_id}`} className="p-3">
                      <div className="grid grid-cols-12 gap-3 items-center">
                        {/* Present toggle + Name - 4 cols */}
                        <div className="col-span-4 flex items-center gap-3">
                          <Switch 
                            checked={entry.is_present} 
                            onCheckedChange={(checked) => {
                              const updated = [...attendanceEntries];
                              updated[index] = { ...updated[index], is_present: checked };
                              setAttendanceEntries(updated);
                            }}
                          />
                          <div className="min-w-0">
                            <p className={`font-medium truncate ${!entry.is_present ? "text-muted-foreground line-through" : ""}`}>
                              {entry.person_name}
                            </p>
                            <p className="text-xs text-muted-foreground">
                              {entry.person_type === "worker" ? "Worker" : "Staff"} • ₹{entry.hourly_rate}/hr
                            </p>
                          </div>
                        </div>
                        
                        {/* Check In - 2 cols */}
                        <div className="col-span-2">
                          <Input 
                            type="time" 
                            value={entry.check_in} 
                            onChange={(e) => updateEntryTime(index, "check_in", e.target.value)}
                            disabled={!entry.is_present}
                            className="h-9"
                          />
                        </div>
                        
                        {/* Check Out - 2 cols */}
                        <div className="col-span-2">
                          <Input 
                            type="time" 
                            value={entry.check_out} 
                            onChange={(e) => updateEntryTime(index, "check_out", e.target.value)}
                            disabled={!entry.is_present}
                            className="h-9"
                          />
                        </div>
                        
                        {/* Hours - 2 cols */}
                        <div className="col-span-2 text-center">
                          <p className="text-sm font-medium">{entry.is_present ? hours.toFixed(1) : "—"} hrs</p>
                        </div>
                        
                        {/* Amount - 2 cols */}
                        <div className="col-span-2 text-right">
                          <p className="font-semibold text-green-600">
                            {entry.is_present ? `₹${amount.toFixed(0)}` : "—"}
                          </p>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Total */}
            <div className="flex items-center justify-between p-4 bg-muted rounded-lg">
              <span className="font-medium">Total Wages for Today</span>
              <span className="text-xl font-bold text-green-600">
                ₹{attendanceEntries
                  .filter(e => e.is_present)
                  .reduce((sum, e) => sum + calculateHours(e.check_in, e.check_out) * e.hourly_rate, 0)
                  .toFixed(0)}
              </span>
            </div>

            {/* Notes */}
            <div className="space-y-2">
              <Label>Notes</Label>
              <Textarea value={attendanceNotes} onChange={(e) => setAttendanceNotes(e.target.value)} placeholder="Any notes for this day..." />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowAttendanceDialog(false)}>Cancel</Button>
            <Button 
              onClick={() => saveAttendanceMutation.mutate()} 
              disabled={saveAttendanceMutation.isPending || attendanceEntries.filter(e => e.is_present).length === 0}
            >
              {saveAttendanceMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Save Attendance
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Make Payment Dialog */}
      <Dialog open={showPaymentDialog} onOpenChange={setShowPaymentDialog}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>Make Payment</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label>Person Type</Label>
              <Select value={paymentPersonType} onValueChange={(v: "staff" | "worker") => { setPaymentPersonType(v); setPaymentPersonId(""); }}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="worker">Worker</SelectItem>
                  <SelectItem value="staff">Staff</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Select Person *</Label>
              <Select value={paymentPersonId} onValueChange={setPaymentPersonId}>
                <SelectTrigger>
                  <SelectValue placeholder="Select person" />
                </SelectTrigger>
                <SelectContent>
                  {paymentPersonType === "worker"
                    ? workers.filter(w => w.is_active).map(w => (
                        <SelectItem key={w.id} value={w.id}>{w.name} ({w.display_id})</SelectItem>
                      ))
                    : staffUsers.map((s: any) => (
                        <SelectItem key={s.user_id} value={s.user_id}>{s.profiles?.full_name}</SelectItem>
                      ))
                  }
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Amount (₹) *</Label>
              <Input type="number" min="0" step="0.01" value={paymentAmount} onChange={(e) => setPaymentAmount(e.target.value)} />
            </div>
            <div className="space-y-2">
              <Label>Payment Method</Label>
              <Select value={paymentMethod} onValueChange={setPaymentMethod}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="cash">Cash</SelectItem>
                  <SelectItem value="bank_transfer">Bank Transfer</SelectItem>
                  <SelectItem value="upi">UPI</SelectItem>
                  <SelectItem value="cheque">Cheque</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label>Notes</Label>
              <Textarea value={paymentNotes} onChange={(e) => setPaymentNotes(e.target.value)} placeholder="Optional notes..." />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowPaymentDialog(false)}>Cancel</Button>
            <Button 
              onClick={() => savePaymentMutation.mutate()} 
              disabled={!paymentPersonId || !paymentAmount || savePaymentMutation.isPending}
            >
              {savePaymentMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Record Payment
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Edit Entries Dialog */}
      <Dialog open={showEditEntriesDialog} onOpenChange={setShowEditEntriesDialog}>
        <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Edit Attendance - {editingRecord?.display_id}</DialogTitle>
          </DialogHeader>
          <div className="space-y-4 py-4">
            {editEntries.map((entry, index) => (
              <div key={entry.id} className="p-4 border rounded-lg">
                <div className="grid grid-cols-12 gap-4 items-center">
                  {/* Name - 3 cols */}
                  <div className="col-span-3">
                    <p className="font-medium">{entry.workers?.name || (entry as any).profiles?.full_name || "Unknown"}</p>
                    <p className="text-xs text-muted-foreground">{entry.worker_id ? "Worker" : "Staff"}</p>
                  </div>
                  
                  {/* Check In - 2 cols */}
                  <div className="col-span-2">
                    <Label className="text-xs">Check In</Label>
                    <Input 
                      type="time" 
                      value={entry.check_in_time || ""} 
                      onChange={(e) => {
                        const updated = [...editEntries];
                        updated[index] = { ...updated[index], check_in_time: e.target.value };
                        setEditEntries(updated);
                      }}
                      className="h-9"
                    />
                  </div>
                  
                  {/* Check Out - 2 cols */}
                  <div className="col-span-2">
                    <Label className="text-xs">Check Out</Label>
                    <Input 
                      type="time" 
                      value={entry.check_out_time || ""} 
                      onChange={(e) => {
                        const updated = [...editEntries];
                        updated[index] = { ...updated[index], check_out_time: e.target.value };
                        setEditEntries(updated);
                      }}
                      className="h-9"
                    />
                  </div>
                  
                  {/* Rate - 2 cols */}
                  <div className="col-span-2">
                    <Label className="text-xs">Rate (₹/hr)</Label>
                    <Input 
                      type="number" 
                      min="0"
                      step="0.01"
                      value={entry.hourly_rate} 
                      onChange={(e) => {
                        const updated = [...editEntries];
                        updated[index] = { ...updated[index], hourly_rate: parseFloat(e.target.value) || 0 };
                        setEditEntries(updated);
                      }}
                      className="h-9"
                    />
                  </div>
                  
                  {/* Amount - 2 cols */}
                  <div className="col-span-2 text-right">
                    <p className="text-xs text-muted-foreground">Earned</p>
                    <p className="font-semibold text-green-600">₹{Number(entry.amount_earned).toFixed(0)}</p>
                  </div>
                  
                  {/* Save button - 1 col */}
                  <div className="col-span-1">
                    <Button 
                      size="sm" 
                      variant="outline"
                      onClick={() => updateEntryMutation.mutate(entry)}
                      disabled={updateEntryMutation.isPending}
                    >
                      Save
                    </Button>
                  </div>
                </div>
              </div>
            ))}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowEditEntriesDialog(false)}>Close</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Worker Confirmation */}
      <AlertDialog open={!!deletingWorkerId} onOpenChange={() => setDeletingWorkerId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Deactivate Worker?</AlertDialogTitle>
            <AlertDialogDescription>
              This will deactivate the worker. They won't appear in attendance forms but their history will be preserved.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={() => deletingWorkerId && deleteWorkerMutation.mutate(deletingWorkerId)}>
              Deactivate
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Shift Rates Dialog */}
      <Dialog open={showShiftRatesDialog} onOpenChange={(open) => { setShowShiftRatesDialog(open); if (!open) resetShiftRateForm(); }}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>Manage Shift Rates</DialogTitle>
            <DialogDescription>
              Define pay rates for different shift durations. Workers are paid proportionally based on hours worked.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            {/* Existing shift rates */}
            <div className="space-y-2">
              <Label className="text-sm font-medium">Current Shift Rates</Label>
              {shiftRates.length === 0 ? (
                <p className="text-sm text-muted-foreground">No shift rates defined yet. Add your first rate below.</p>
              ) : (
                <div className="border rounded-lg divide-y">
                  {shiftRates.map((rate: any) => (
                    <div key={rate.id} className="p-3 flex items-center justify-between">
                      <div>
                        <p className="font-medium">{rate.shift_name}</p>
                        <p className="text-sm text-muted-foreground">
                          {rate.duration_hours} hours = ₹{rate.rate_amount.toFixed(2)}
                        </p>
                      </div>
                      <div className="flex gap-2">
                        <Button 
                          variant="ghost" 
                          size="sm"
                          onClick={() => {
                            setEditingShiftRate(rate);
                            setShiftRateName(rate.shift_name);
                            setShiftRateDuration(String(rate.duration_hours));
                            setShiftRateAmount(String(rate.rate_amount));
                          }}
                        >
                          <Pencil className="h-4 w-4" />
                        </Button>
                        <Button 
                          variant="ghost" 
                          size="sm"
                          onClick={() => deleteShiftRateMutation.mutate(rate.id)}
                          disabled={deleteShiftRateMutation.isPending}
                        >
                          <Trash2 className="h-4 w-4 text-destructive" />
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Add/Edit form */}
            <div className="border-t pt-4">
              <Label className="text-sm font-medium">{editingShiftRate ? "Edit Shift Rate" : "Add New Shift Rate"}</Label>
              <div className="grid grid-cols-3 gap-3 mt-2">
                <div className="space-y-1">
                  <Label className="text-xs text-muted-foreground">Name</Label>
                  <Input 
                    value={shiftRateName} 
                    onChange={(e) => setShiftRateName(e.target.value)} 
                    placeholder="e.g., Full Day"
                  />
                </div>
                <div className="space-y-1">
                  <Label className="text-xs text-muted-foreground">Duration (hours)</Label>
                  <Input 
                    type="number" 
                    min="0.5" 
                    step="0.5"
                    value={shiftRateDuration} 
                    onChange={(e) => setShiftRateDuration(e.target.value)} 
                    placeholder="e.g., 9"
                  />
                </div>
                <div className="space-y-1">
                  <Label className="text-xs text-muted-foreground">Rate (₹)</Label>
                  <Input 
                    type="number" 
                    min="0" 
                    step="0.01"
                    value={shiftRateAmount} 
                    onChange={(e) => setShiftRateAmount(e.target.value)} 
                    placeholder="e.g., 500"
                  />
                </div>
              </div>
              <div className="flex gap-2 mt-3">
                <Button 
                  onClick={() => saveShiftRateMutation.mutate()} 
                  disabled={!shiftRateName.trim() || !shiftRateDuration || !shiftRateAmount || saveShiftRateMutation.isPending}
                  size="sm"
                >
                  {saveShiftRateMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                  {editingShiftRate ? "Update" : "Add"} Rate
                </Button>
                {editingShiftRate && (
                  <Button variant="outline" size="sm" onClick={resetShiftRateForm}>Cancel Edit</Button>
                )}
              </div>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowShiftRatesDialog(false)}>Close</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect, useMemo } from "react";
import { useNavigate, useParams, useLocation } from "react-router-dom";
import { PageHeader } from "@/components/shared/PageHeader";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { Loader2, Plus, Trash2, ArrowLeft, Save, FileText } from "lucide-react";
import { toast } from "sonner";
import { logActivity } from "@/lib/activityLogger";

interface InvoiceItem {
  id?: string;
  product_id: string | null;
  product_name: string;
  hsn_code: string;
  quantity: number;
  unit_price: number;
  tax_rate: number;
  tax_amount: number;
  discount_amount: number;
  total_amount: number;
  sale_item_id?: string;
}

const InvoiceForm = () => {
  const navigate = useNavigate();
  const { id } = useParams();
  const location = useLocation();
  const { user } = useAuth();
  const qc = useQueryClient();
  const isEdit = !!id && id !== "new";

  // Form state
  const [invoiceNumber, setInvoiceNumber] = useState("");
  const [invoiceDate, setInvoiceDate] = useState(new Date().toISOString().split("T")[0]);
  const [customerId, setCustomerId] = useState("");
  const [storeId, setStoreId] = useState("");
  const [customerName, setCustomerName] = useState("");
  const [customerAddress, setCustomerAddress] = useState("");
  const [customerPhone, setCustomerPhone] = useState("");
  const [customerGstin, setCustomerGstin] = useState("");
  const [customerState, setCustomerState] = useState("");
  const [isInterState, setIsInterState] = useState(false);
  const [warehouseId, setWarehouseId] = useState("");
  const [notes, setNotes] = useState("");
  const [items, setItems] = useState<InvoiceItem[]>([]);
  const [selectedSales, setSelectedSales] = useState<string[]>(location.state?.saleIds || []);
  const [saving, setSaving] = useState(false);
  const [loadingNext, setLoadingNext] = useState(true);

  // Fetch business info for state comparison
  const { data: businessInfo } = useQuery({
    queryKey: ["business-info"],
    queryFn: async () => {
      const { data } = await supabase
        .from("business_info")
        .select("*")
        .single();
      return data;
    },
  });

  // Fetch next invoice number
  useEffect(() => {
    if (!isEdit) {
      supabase.rpc("get_next_invoice_number").then(({ data }) => {
        if (data) setInvoiceNumber(data);
        setLoadingNext(false);
      });
    } else {
      setLoadingNext(false);
    }
  }, [isEdit]);

  // Fetch customers
  const { data: customers = [] } = useQuery({
    queryKey: ["customers-for-invoice"],
    queryFn: async () => {
      const { data } = await supabase
        .from("customers")
        .select("id, name, phone, address")
        .eq("is_active", true)
        .order("name");
      return data || [];
    },
  });

  // Fetch stores for selected customer
  const { data: stores = [] } = useQuery({
    queryKey: ["stores-for-invoice", customerId],
    queryFn: async () => {
      if (!customerId) return [];
      const { data } = await supabase
        .from("stores")
        .select("id, name, address, phone, store_type_id")
        .eq("customer_id", customerId)
        .eq("is_active", true);
      return data || [];
    },
    enabled: !!customerId,
  });

  // Get selected store's type for product filtering
  const selectedStore = stores.find((s: any) => s.id === storeId);
  const selectedStoreTypeId = selectedStore?.store_type_id;

  // Fetch warehouses
  const { data: warehouses = [] } = useQuery({
    queryKey: ["warehouses-for-invoice"],
    queryFn: async () => {
      const { data } = await supabase
        .from("warehouses")
        .select("id, name, address, city, state, is_default")
        .eq("is_active", true);
      return data || [];
    },
  });

  // Fetch products - filtered by store type if selected, else all active products
  const { data: products = [] } = useQuery({
    queryKey: ["products-for-invoice", selectedStoreTypeId],
    queryFn: async () => {
      // If store is selected, get products for that store type
      if (selectedStoreTypeId) {
        const { data: storeTypeProducts } = await supabase
          .from("store_type_products")
          .select("product_id, products(id, name, hsn_code, base_price, gst_rate)")
          .eq("store_type_id", selectedStoreTypeId);
        
        if (storeTypeProducts && storeTypeProducts.length > 0) {
          return storeTypeProducts.map((stp: any) => stp.products).filter(Boolean);
        }
      }
      
      // Fallback: all active products (when no store selected or no store_type_products configured)
      const { data } = await supabase
        .from("products")
        .select("id, name, hsn_code, base_price, gst_rate")
        .eq("is_active", true);
      return data || [];
    },
  });

  // Fetch uninvoiced sales for customer/store
  const { data: availableSales = [] } = useQuery({
    queryKey: ["uninvoiced-sales", customerId, storeId],
    queryFn: async () => {
      if (!customerId) return [];
      let query = supabase
        .from("sales")
        .select(`
          id, display_id, created_at, total_amount,
          sale_items(id, product_id, quantity, unit_price, total_price, products(name, hsn_code, gst_rate))
        `)
        .eq("customer_id", customerId)
        .eq("has_invoice", false);
      
      if (storeId) {
        query = query.eq("store_id", storeId);
      }
      
      const { data } = await query.order("created_at", { ascending: false });
      return data || [];
    },
    enabled: !!customerId,
  });

  // Set default warehouse
  useEffect(() => {
    if (warehouses.length > 0 && !warehouseId) {
      const defaultWh = warehouses.find((w: any) => w.is_default);
      setWarehouseId(defaultWh?.id || warehouses[0].id);
    }
  }, [warehouses, warehouseId]);

  // Auto-fill customer details
  useEffect(() => {
    if (customerId) {
      const customer = customers.find((c: any) => c.id === customerId);
      if (customer) {
        setCustomerName(customer.name);
        setCustomerPhone(customer.phone || "");
        setCustomerAddress(customer.address || "");
      }
    }
  }, [customerId, customers]);

  // Auto-fill store details (override customer if store selected)
  useEffect(() => {
    if (storeId) {
      const store = stores.find((s: any) => s.id === storeId);
      if (store) {
        setCustomerAddress(store.address || customerAddress);
        setCustomerPhone(store.phone || customerPhone);
        setCustomerGstin(store.gstin || "");
      }
    }
  }, [storeId, stores]);

  // Load items from selected sales
  useEffect(() => {
    if (selectedSales.length > 0 && availableSales.length > 0) {
      const newItems: InvoiceItem[] = [];
      selectedSales.forEach((saleId) => {
        const sale = availableSales.find((s: any) => s.id === saleId);
        if (sale?.sale_items) {
          sale.sale_items.forEach((item: any) => {
            const lineTotal = Number(item.total_price ?? (item.quantity * item.unit_price) ?? 0);
            const taxRate = Number(item.products?.gst_rate || 0);
            const taxableAmount = taxRate > 0 ? lineTotal / (1 + taxRate / 100) : lineTotal;
            const lineTax = lineTotal - taxableAmount;

            newItems.push({
              product_id: item.product_id,
              product_name: item.products?.name || "Unknown",
              hsn_code: item.products?.hsn_code || "",
              quantity: item.quantity,
              unit_price: item.unit_price,
              tax_rate: taxRate,
              tax_amount: Math.round(lineTax * 100) / 100,
              discount_amount: 0,
              total_amount: Math.round(lineTotal * 100) / 100,
              sale_item_id: item.id,
            });
          });
        }
      });
      setItems(newItems);
    }
  }, [selectedSales, availableSales]);

  // Calculate totals with CGST/SGST/IGST breakdown
  const totals = useMemo(() => {
    // Calculate taxable amount (price / (1 + gst_rate/100) for GST-inclusive prices)
    let taxableAmount = 0;
    let totalTax = 0;
    let discountAmount = 0;
    
    items.forEach(item => {
      const lineTotal = item.quantity * item.unit_price;
      // Assume prices are GST-inclusive: base = price / (1 + gst_rate/100)
      const taxRate = item.tax_rate || 0;
      const baseAmount = taxRate > 0 ? lineTotal / (1 + taxRate / 100) : lineTotal;
      const lineTax = lineTotal - baseAmount;
      
      taxableAmount += baseAmount;
      totalTax += lineTax;
      discountAmount += item.discount_amount;
    });

    // Split tax based on inter-state or intra-state
    const cgstAmount = isInterState ? 0 : totalTax / 2;
    const sgstAmount = isInterState ? 0 : totalTax / 2;
    const igstAmount = isInterState ? totalTax : 0;
    
    const grandTotal = taxableAmount + totalTax - discountAmount;
    
    return { 
      taxableAmount: Math.round(taxableAmount * 100) / 100,
      cgstAmount: Math.round(cgstAmount * 100) / 100,
      sgstAmount: Math.round(sgstAmount * 100) / 100,
      igstAmount: Math.round(igstAmount * 100) / 100,
      totalTax: Math.round(totalTax * 100) / 100,
      discountAmount: Math.round(discountAmount * 100) / 100,
      grandTotal: Math.round(grandTotal * 100) / 100
    };
  }, [items, isInterState]);

  const handleSaleToggle = (saleId: string) => {
    setSelectedSales((prev) =>
      prev.includes(saleId) ? prev.filter((id) => id !== saleId) : [...prev, saleId]
    );
  };

  const addEmptyItem = () => {
    setItems([...items, {
      product_id: null,
      product_name: "",
      hsn_code: "",
      quantity: 1,
      unit_price: 0,
      tax_rate: 0,
      tax_amount: 0,
      discount_amount: 0,
      total_amount: 0,
    }]);
  };

  const updateItem = (index: number, field: keyof InvoiceItem, value: any) => {
    const newItems = [...items];
    const item = { ...newItems[index], [field]: value };
    
    // If product selected, auto-fill details
    if (field === "product_id" && value) {
      const product = products.find((p: any) => p.id === value);
      if (product) {
        item.product_name = product.name;
        item.hsn_code = product.hsn_code || "";
        item.unit_price = product.base_price || 0;
        item.tax_rate = product.gst_rate || 0;
      }
    }
    
    // Recalculate amounts with GST-inclusive pricing.
    const grossLine = item.quantity * item.unit_price;
    const effectiveLine = Math.max(0, grossLine - (item.discount_amount || 0));
    const taxRate = item.tax_rate || 0;
    const taxableAmount = taxRate > 0 ? effectiveLine / (1 + taxRate / 100) : effectiveLine;
    item.tax_amount = effectiveLine - taxableAmount;
    item.total_amount = effectiveLine;
    
    newItems[index] = item;
    setItems(newItems);
  };

  const removeItem = (index: number) => {
    setItems(items.filter((_, i) => i !== index));
  };

  const handleSubmit = async (status: "draft" | "issued") => {
    if (!invoiceNumber.trim()) {
      toast.error("Invoice number is required");
      return;
    }
    if (!customerName.trim()) {
      toast.error("Customer name is required");
      return;
    }
    if (items.length === 0) {
      toast.error("Add at least one item");
      return;
    }

    setSaving(true);

    try {
      const warehouse = warehouses.find((w: any) => w.id === warehouseId);
      const dispatchAddress = warehouse 
        ? `${warehouse.name}, ${warehouse.address || ""}, ${warehouse.city || ""}, ${warehouse.state || ""}`.trim()
        : "";

      // Create invoice
      const invoiceData = {
        invoice_number: invoiceNumber.trim(),
        invoice_date: invoiceDate,
        customer_id: customerId || null,
        store_id: storeId || null,
        customer_name: customerName.trim(),
        customer_address: customerAddress.trim() || null,
        customer_phone: customerPhone.trim() || null,
        customer_gstin: customerGstin.trim() || null,
        buyer_state: customerState.trim() || null,
        dispatch_warehouse_id: warehouseId || null,
        dispatch_address: dispatchAddress || null,
        is_inter_state: isInterState,
        taxable_amount: totals.taxableAmount,
        cgst_rate: isInterState ? null : (totals.cgstAmount > 0 ? (totals.cgstAmount / totals.taxableAmount * 100) : 0),
        cgst_amount: totals.cgstAmount,
        sgst_rate: isInterState ? null : (totals.sgstAmount > 0 ? (totals.sgstAmount / totals.taxableAmount * 100) : 0),
        sgst_amount: totals.sgstAmount,
        igst_rate: isInterState ? (totals.igstAmount > 0 ? (totals.igstAmount / totals.taxableAmount * 100) : 0) : null,
        igst_amount: totals.igstAmount,
        subtotal: totals.taxableAmount,
        tax_amount: totals.totalTax,
        discount_amount: totals.discountAmount,
        total_amount: totals.grandTotal,
        status,
        notes: notes.trim() || null,
        created_by: user!.id,
      };

      const { data: invoice, error: invError } = await supabase
        .from("invoices")
        .insert(invoiceData)
        .select()
        .single();

      if (invError) throw invError;

      // Create invoice items
      const itemsData = items.map((item) => {
        const lineTotal = Math.max(0, item.quantity * item.unit_price - (item.discount_amount || 0));
        const taxRate = item.tax_rate || 0;
        const taxableAmount = taxRate > 0 ? lineTotal / (1 + taxRate / 100) : lineTotal;
        const lineTax = lineTotal - taxableAmount;
        
        return {
          invoice_id: invoice.id,
          product_id: item.product_id,
          product_name: item.product_name,
          hsn_code: item.hsn_code || null,
          quantity: item.quantity,
          unit_price: item.unit_price,
          gst_rate: taxRate,
          taxable_amount: Math.round(taxableAmount * 100) / 100,
          cgst_amount: isInterState ? 0 : Math.round(lineTax / 2 * 100) / 100,
          sgst_amount: isInterState ? 0 : Math.round(lineTax / 2 * 100) / 100,
          igst_amount: isInterState ? Math.round(lineTax * 100) / 100 : 0,
          tax_rate: taxRate,
          tax_amount: Math.round(lineTax * 100) / 100,
          discount_amount: item.discount_amount,
          total_amount: lineTotal,
          sale_item_id: item.sale_item_id || null,
        };
      });

      const { error: itemsError } = await supabase
        .from("invoice_items")
        .insert(itemsData);

      if (itemsError) throw itemsError;

      // Link sales to invoice
      if (selectedSales.length > 0) {
        const salesLinks = selectedSales.map((saleId) => ({
          invoice_id: invoice.id,
          sale_id: saleId,
        }));

        const { error: linkError } = await supabase
          .from("invoice_sales")
          .insert(salesLinks);

        if (linkError) throw linkError;
      }

      toast.success(`Invoice ${invoiceNumber} ${status === "issued" ? "issued" : "saved as draft"}`);
      logActivity(user!.id, `Created invoice ${invoiceNumber}`, "invoice");
      qc.invalidateQueries({ queryKey: ["invoices"] });
      qc.invalidateQueries({ queryKey: ["sales"] });
      navigate("/invoices");
    } catch (error: any) {
      toast.error(error.message || "Failed to create invoice");
    } finally {
      setSaving(false);
    }
  };

  if (loadingNext) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      <PageHeader
        title={isEdit ? "Edit Invoice" : "Create Invoice"}
        subtitle="Generate a tax invoice"
        backButton={{ label: "Back to Invoices", onClick: () => navigate("/invoices") }}
      />

      <div className="grid gap-6 lg:grid-cols-3">
        {/* Left Column - Main Form */}
        <div className="lg:col-span-2 space-y-6">
          {/* Invoice Details */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Invoice Details</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Invoice Number *</Label>
                  <Input
                    value={invoiceNumber}
                    onChange={(e) => setInvoiceNumber(e.target.value)}
                    placeholder="INV-000001"
                    className="mt-1 font-mono"
                  />
                </div>
                <div>
                  <Label>Invoice Date *</Label>
                  <Input
                    type="date"
                    value={invoiceDate}
                    onChange={(e) => setInvoiceDate(e.target.value)}
                    className="mt-1"
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Customer Details */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Bill To</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Select Customer</Label>
                  <Select value={customerId} onValueChange={setCustomerId}>
                    <SelectTrigger className="mt-1">
                      <SelectValue placeholder="Select customer" />
                    </SelectTrigger>
                    <SelectContent>
                      {customers.map((c: any) => (
                        <SelectItem key={c.id} value={c.id}>{c.name}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label>Select Store</Label>
                  <Select value={storeId} onValueChange={setStoreId} disabled={!customerId}>
                    <SelectTrigger className="mt-1">
                      <SelectValue placeholder={customerId ? "Select store" : "Select customer first"} />
                    </SelectTrigger>
                    <SelectContent>
                      {stores.map((s: any) => (
                        <SelectItem key={s.id} value={s.id}>{s.name}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Customer Name *</Label>
                  <Input
                    value={customerName}
                    onChange={(e) => setCustomerName(e.target.value)}
                    placeholder="Customer name"
                    className="mt-1"
                  />
                </div>
                <div>
                  <Label>Phone</Label>
                  <Input
                    value={customerPhone}
                    onChange={(e) => setCustomerPhone(e.target.value)}
                    placeholder="Phone number"
                    className="mt-1"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Address</Label>
                  <Textarea
                    value={customerAddress}
                    onChange={(e) => setCustomerAddress(e.target.value)}
                    placeholder="Billing address"
                    className="mt-1"
                    rows={2}
                  />
                </div>
                <div>
                  <Label>GSTIN</Label>
                  <Input
                    value={customerGstin}
                    onChange={(e) => setCustomerGstin(e.target.value.toUpperCase())}
                    placeholder="Customer GSTIN"
                    className="mt-1 font-mono"
                    maxLength={15}
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Link Sales */}
          {customerId && availableSales.length > 0 && (
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Link Sales (Optional)</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2 max-h-48 overflow-y-auto">
                  {availableSales.map((sale: any) => (
                    <div
                      key={sale.id}
                      className={`flex items-center gap-3 p-3 rounded-lg border cursor-pointer transition-colors ${
                        selectedSales.includes(sale.id) ? "border-primary bg-primary/5" : "hover:bg-muted/50"
                      }`}
                      onClick={() => handleSaleToggle(sale.id)}
                    >
                      <Checkbox checked={selectedSales.includes(sale.id)} />
                      <div className="flex-1">
                        <p className="font-mono text-sm font-medium">{sale.display_id}</p>
                        <p className="text-xs text-muted-foreground">
                          {new Date(sale.created_at).toLocaleDateString("en-IN")} • {sale.sale_items?.length || 0} items
                        </p>
                      </div>
                      <span className="font-semibold">₹{Number(sale.total_amount).toLocaleString()}</span>
                    </div>
                  ))}
                </div>
              </CardContent>
            </Card>
          )}

          {/* Invoice Items */}
          <Card>
            <CardHeader className="flex flex-row items-center justify-between">
              <CardTitle className="text-base">Items</CardTitle>
              <Button variant="outline" size="sm" onClick={addEmptyItem}>
                <Plus className="h-4 w-4 mr-1" /> Add Item
              </Button>
            </CardHeader>
            <CardContent>
              {items.length === 0 ? (
                <p className="text-center text-muted-foreground py-8">
                  {selectedSales.length > 0 ? "Loading items from sales..." : "No items added. Select sales above or add items manually."}
                </p>
              ) : (
                <div className="space-y-3">
                  {items.map((item, index) => (
                    <div key={index} className="grid grid-cols-12 gap-2 items-end p-3 bg-muted/30 rounded-lg">
                      <div className="col-span-4">
                        <Label className="text-xs">Product</Label>
                        <Select
                          value={item.product_id || ""}
                          onValueChange={(v) => updateItem(index, "product_id", v)}
                        >
                          <SelectTrigger className="mt-1 h-9">
                            <SelectValue placeholder="Select product" />
                          </SelectTrigger>
                          <SelectContent>
                            {products.map((p: any) => (
                              <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      </div>
                      <div className="col-span-2">
                        <Label className="text-xs">HSN</Label>
                        <Input
                          value={item.hsn_code}
                          onChange={(e) => updateItem(index, "hsn_code", e.target.value)}
                          className="mt-1 h-9 font-mono text-xs"
                        />
                      </div>
                      <div className="col-span-1">
                        <Label className="text-xs">Qty</Label>
                        <Input
                          type="number"
                          min="1"
                          value={item.quantity}
                          onChange={(e) => updateItem(index, "quantity", parseFloat(e.target.value) || 0)}
                          className="mt-1 h-9"
                        />
                      </div>
                      <div className="col-span-2">
                        <Label className="text-xs">Price</Label>
                        <Input
                          type="number"
                          min="0"
                          step="0.01"
                          value={item.unit_price}
                          onChange={(e) => updateItem(index, "unit_price", parseFloat(e.target.value) || 0)}
                          className="mt-1 h-9"
                        />
                      </div>
                      <div className="col-span-2">
                        <Label className="text-xs">Total</Label>
                        <div className="mt-1 h-9 flex items-center font-semibold">
                          ₹{item.total_amount.toLocaleString()}
                        </div>
                      </div>
                      <div className="col-span-1">
                        <Button
                          variant="ghost"
                          size="icon"
                          className="h-9 w-9 text-destructive"
                          onClick={() => removeItem(index)}
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Notes */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Notes</CardTitle>
            </CardHeader>
            <CardContent>
              <Textarea
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
                placeholder="Additional notes for this invoice..."
                rows={3}
              />
            </CardContent>
          </Card>
        </div>

        {/* Right Column - Summary & Actions */}
        <div className="space-y-6">
          {/* Dispatch From */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Dispatch From</CardTitle>
            </CardHeader>
            <CardContent>
              <Select value={warehouseId} onValueChange={setWarehouseId}>
                <SelectTrigger>
                  <SelectValue placeholder="Select warehouse" />
                </SelectTrigger>
                <SelectContent>
                  {warehouses.map((w: any) => (
                    <SelectItem key={w.id} value={w.id}>
                      {w.name} {w.is_default && "(Default)"}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </CardContent>
          </Card>

          {/* GST Type Toggle */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">GST Type</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <input
                    type="radio"
                    id="intra-state"
                    name="gst-type"
                    checked={!isInterState}
                    onChange={() => setIsInterState(false)}
                    className="w-4 h-4"
                  />
                  <label htmlFor="intra-state" className="text-sm">Intra-State (CGST + SGST)</label>
                </div>
                <div className="flex items-center gap-2">
                  <input
                    type="radio"
                    id="inter-state"
                    name="gst-type"
                    checked={isInterState}
                    onChange={() => setIsInterState(true)}
                    className="w-4 h-4"
                  />
                  <label htmlFor="inter-state" className="text-sm">Inter-State (IGST)</label>
                </div>
              </div>
              {businessInfo?.state && (
                <p className="text-xs text-muted-foreground mt-2">
                  Business State: {businessInfo.state}
                </p>
              )}
            </CardContent>
          </Card>

          {/* Summary */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Tax Summary</CardTitle>
            </CardHeader>
            <CardContent className="space-y-2">
              <div className="flex justify-between text-sm">
                <span className="text-muted-foreground">Taxable Amount</span>
                <span>₹{totals.taxableAmount.toLocaleString()}</span>
              </div>
              
              {!isInterState ? (
                <>
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">CGST</span>
                    <span>₹{totals.cgstAmount.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-muted-foreground">SGST</span>
                    <span>₹{totals.sgstAmount.toLocaleString()}</span>
                  </div>
                </>
              ) : (
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">IGST</span>
                  <span>₹{totals.igstAmount.toLocaleString()}</span>
                </div>
              )}
              
              {totals.discountAmount > 0 && (
                <div className="flex justify-between text-sm">
                  <span className="text-muted-foreground">Discount</span>
                  <span className="text-green-600">-₹{totals.discountAmount.toLocaleString()}</span>
                </div>
              )}
              <div className="flex justify-between font-bold text-lg pt-3 border-t">
                <span>Grand Total</span>
                <span className="text-primary">₹{totals.grandTotal.toLocaleString()}</span>
              </div>
            </CardContent>
          </Card>

          {/* Actions */}
          <div className="space-y-3">
            <Button
              className="w-full"
              onClick={() => handleSubmit("issued")}
              disabled={saving || items.length === 0}
            >
              {saving ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <FileText className="mr-2 h-4 w-4" />}
              Issue Invoice
            </Button>
            <Button
              variant="outline"
              className="w-full"
              onClick={() => handleSubmit("draft")}
              disabled={saving || items.length === 0}
            >
              <Save className="mr-2 h-4 w-4" />
              Save as Draft
            </Button>
            <Button
              variant="ghost"
              className="w-full"
              onClick={() => navigate("/invoices")}
              disabled={saving}
            >
              <ArrowLeft className="mr-2 h-4 w-4" />
              Cancel
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default InvoiceForm;

import { useState, useRef } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { PageHeader } from "@/components/shared/PageHeader";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Loader2, Printer, Download, ArrowLeft, Share2 } from "lucide-react";
import { toast } from "sonner";

// Number to words converter
const numberToWords = (num: number): string => {
  const ones = ["", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine", "Ten",
    "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"];
  const tens = ["", "", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"];
  
  const convert = (n: number): string => {
    if (n < 20) return ones[n];
    if (n < 100) return tens[Math.floor(n / 10)] + (n % 10 ? " " + ones[n % 10] : "");
    if (n < 1000) return ones[Math.floor(n / 100)] + " Hundred" + (n % 100 ? " " + convert(n % 100) : "");
    if (n < 100000) return convert(Math.floor(n / 1000)) + " Thousand" + (n % 1000 ? " " + convert(n % 1000) : "");
    if (n < 10000000) return convert(Math.floor(n / 100000)) + " Lakh" + (n % 100000 ? " " + convert(n % 100000) : "");
    return convert(Math.floor(n / 10000000)) + " Crore" + (n % 10000000 ? " " + convert(n % 10000000) : "");
  };
  
  const rupees = Math.floor(num);
  const paise = Math.round((num - rupees) * 100);
  
  let result = "Rupees " + convert(rupees);
  if (paise > 0) {
    result += " and " + convert(paise) + " Paise";
  }
  return result + " Only";
};

const InvoiceView = () => {
  const navigate = useNavigate();
  const { id } = useParams();
  const printRef = useRef<HTMLDivElement>(null);

  // Fetch invoice
  const { data: invoice, isLoading } = useQuery({
    queryKey: ["invoice", id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("invoices")
        .select(`
          *,
          customers(name, phone),
          stores(name),
          warehouses:dispatch_warehouse_id(name, address, city, pincode, phone),
          invoice_items(*),
          invoice_sales(sale_id, sales(display_id))
        `)
        .eq("id", id)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: !!id,
  });

  // Fetch company settings
  const { data: settings = {} } = useQuery({
    queryKey: ["company-settings-invoice"],
    queryFn: async () => {
      const { data } = await supabase.from("company_settings").select("key, value");
      const map: Record<string, string> = {};
      data?.forEach((s: any) => { map[s.key] = s.value; });
      return map;
    },
  });

  // Fetch business info for GST details
  const { data: businessInfo } = useQuery({
    queryKey: ["business-info-invoice"],
    queryFn: async () => {
      const { data } = await supabase.from("business_info").select("*").single();
      return data;
    },
  });

  const handlePrint = () => {
    window.print();
  };

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Invoice ${invoice?.invoice_number}`,
          text: `Invoice ${invoice?.invoice_number} - ₹${Number(invoice?.total_amount).toLocaleString()}`,
          url: window.location.href,
        });
      } catch (err) {
        // User cancelled share
      }
    } else {
      navigator.clipboard.writeText(window.location.href);
      toast.success("Link copied to clipboard");
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (!invoice) {
    return (
      <div className="text-center py-20">
        <p className="text-muted-foreground">Invoice not found</p>
        <Button variant="link" onClick={() => navigate("/invoices")}>
          Back to Invoices
        </Button>
      </div>
    );
  }

  const amountInWords = numberToWords(Number(invoice.total_amount));

  const renderPrintCopy = (copyTitle: string, isLast: boolean) => (
    <section className={`mx-auto max-w-4xl bg-white p-8 text-black ${isLast ? "" : "print:break-after-page"}`}>
      <div className="flex justify-between items-start mb-6 pb-4 border-b-2 border-black">
        <div>
          <h1 className="text-2xl font-bold">{businessInfo?.name || settings.business_name || "Your Company"}</h1>
          <p className="text-sm whitespace-pre-line">
            {businessInfo?.address || settings.business_address}
            {(businessInfo?.city || settings.business_city) && `, ${businessInfo?.city || settings.business_city}`}
            {(businessInfo?.pincode || settings.business_pincode) && ` - ${businessInfo?.pincode || settings.business_pincode}`}
          </p>
          {(businessInfo?.phone || settings.business_phone) && <p className="text-sm">Phone: {businessInfo?.phone || settings.business_phone}</p>}
          {(businessInfo?.email || settings.business_email) && <p className="text-sm">Email: {businessInfo?.email || settings.business_email}</p>}
          {(businessInfo?.gstin || settings.business_gstin) && <p className="text-sm font-mono font-semibold">GSTIN: {businessInfo?.gstin || settings.business_gstin}</p>}
        </div>
        <div className="text-right">
          <h2 className="text-3xl font-bold text-primary">TAX INVOICE</h2>
          <p className="font-mono text-lg font-semibold mt-2">{invoice.invoice_number}</p>
          <p className="text-sm">Date: {new Date(invoice.invoice_date).toLocaleDateString("en-IN", { day: "2-digit", month: "short", year: "numeric" })}</p>
          <Badge variant="outline" className="mt-2">{copyTitle}</Badge>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-8 mb-6">
        <div>
          <h3 className="font-semibold text-sm text-muted-foreground mb-2">BILL TO</h3>
          <p className="font-semibold">{invoice.customer_name}</p>
          {invoice.stores?.name && <p className="text-sm">{invoice.stores.name}</p>}
          {invoice.customer_address && <p className="text-sm whitespace-pre-line">{invoice.customer_address}</p>}
          {invoice.customer_phone && <p className="text-sm">Phone: {invoice.customer_phone}</p>}
          {invoice.customer_gstin && <p className="text-sm font-mono">GSTIN: {invoice.customer_gstin}</p>}
        </div>
        <div>
          <h3 className="font-semibold text-sm text-muted-foreground mb-2">DISPATCH FROM</h3>
          {invoice.warehouses ? (
            <>
              <p className="font-semibold">{invoice.warehouses.name}</p>
              <p className="text-sm whitespace-pre-line">
                {invoice.warehouses.address}
                {invoice.warehouses.city && `, ${invoice.warehouses.city}`}
                {invoice.warehouses.pincode && ` - ${invoice.warehouses.pincode}`}
              </p>
              {invoice.warehouses.phone && <p className="text-sm">Phone: {invoice.warehouses.phone}</p>}
            </>
          ) : (
            <p className="text-sm text-muted-foreground">—</p>
          )}
        </div>
      </div>

      <table className="w-full mb-6 text-sm border-collapse">
        <thead>
          <tr className="bg-gray-100">
            <th className="text-left p-2 border">#</th>
            <th className="text-left p-2 border">Description</th>
            <th className="text-left p-2 border">HSN</th>
            <th className="text-right p-2 border">Qty</th>
            <th className="text-right p-2 border">Rate</th>
            <th className="text-right p-2 border">Taxable</th>
            <th className="text-right p-2 border">GST %</th>
            <th className="text-right p-2 border">Amount</th>
          </tr>
        </thead>
        <tbody>
          {invoice.invoice_items?.map((item: any, index: number) => {
            const lineTotal = Number(item.total_amount ?? item.quantity * item.unit_price);
            const gstRate = item.gst_rate || item.tax_rate || 0;
            const taxableAmt = item.taxable_amount || (gstRate > 0 ? lineTotal / (1 + gstRate / 100) : lineTotal);
            return (
              <tr key={item.id}>
                <td className="p-2 border">{index + 1}</td>
                <td className="p-2 border">{item.product_name}</td>
                <td className="p-2 border font-mono text-xs">{item.hsn_code || "—"}</td>
                <td className="p-2 border text-right">{item.quantity}</td>
                <td className="p-2 border text-right">₹{Number(item.unit_price).toLocaleString()}</td>
                <td className="p-2 border text-right">₹{Number(taxableAmt).toLocaleString()}</td>
                <td className="p-2 border text-right">{gstRate}%</td>
                <td className="p-2 border text-right font-semibold">₹{Number(lineTotal).toLocaleString()}</td>
              </tr>
            );
          })}
        </tbody>
      </table>

      <div className="flex justify-end mb-6">
        <div className="w-80 border rounded-lg overflow-hidden">
          <div className="flex justify-between py-2 px-3 bg-gray-50 border-b">
            <span>Taxable Amount</span>
            <span className="font-medium">₹{Number(invoice.taxable_amount || invoice.subtotal).toLocaleString()}</span>
          </div>
          {invoice.is_inter_state ? (
            <div className="flex justify-between py-2 px-3 border-b">
              <span>IGST</span>
              <span>₹{Number(invoice.igst_amount || invoice.tax_amount).toLocaleString()}</span>
            </div>
          ) : (
            <>
              <div className="flex justify-between py-2 px-3 border-b">
                <span>CGST</span>
                <span>₹{Number(invoice.cgst_amount || (invoice.tax_amount / 2)).toLocaleString()}</span>
              </div>
              <div className="flex justify-between py-2 px-3 border-b">
                <span>SGST</span>
                <span>₹{Number(invoice.sgst_amount || (invoice.tax_amount / 2)).toLocaleString()}</span>
              </div>
            </>
          )}
          {Number(invoice.discount_amount) > 0 && (
            <div className="flex justify-between py-2 px-3 text-green-600 border-b">
              <span>Discount</span>
              <span>-₹{Number(invoice.discount_amount).toLocaleString()}</span>
            </div>
          )}
          <div className="flex justify-between py-3 px-3 bg-primary/10 font-bold text-lg">
            <span>Grand Total</span>
            <span>₹{Number(invoice.total_amount).toLocaleString()}</span>
          </div>
        </div>
      </div>

      <div className="bg-gray-50 p-3 rounded">
        <p className="text-sm"><span className="font-semibold">Amount in Words: </span>{amountInWords}</p>
      </div>
    </section>
  );

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Header - Hide in print */}
      <div className="print:hidden">
        <PageHeader
          title={`Invoice ${invoice.invoice_number}`}
          subtitle={invoice.status === "cancelled" ? "This invoice has been cancelled" : undefined}
          backButton={{ label: "Back to Invoices", onClick: () => navigate("/invoices") }}
        />
        
        <div className="flex gap-2 mt-4">
          <Button onClick={handlePrint}>
            <Printer className="mr-2 h-4 w-4" /> Print
          </Button>
          <Button variant="outline" onClick={handleShare}>
            <Share2 className="mr-2 h-4 w-4" /> Share
          </Button>
        </div>
      </div>

      {/* Invoice Template */}
      <Card className="max-w-4xl mx-auto print:hidden">
        <CardContent className="p-8 print:p-4" ref={printRef}>
          {/* Cancelled Watermark */}
          {invoice.status === "cancelled" && (
            <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
              <span className="text-red-200 text-8xl font-bold rotate-[-30deg] opacity-50">
                CANCELLED
              </span>
            </div>
          )}

          {/* Header */}
          <div className="flex justify-between items-start mb-8 pb-4 border-b-2 border-gray-800">
            <div>
              {settings.business_logo_url && (
                <img src={settings.business_logo_url} alt="Logo" className="h-16 mb-2" />
              )}
              <h1 className="text-2xl font-bold">{businessInfo?.name || settings.business_name || "Your Company"}</h1>
              <p className="text-sm text-muted-foreground whitespace-pre-line">
                {businessInfo?.address || settings.business_address}
                {(businessInfo?.city || settings.business_city) && `, ${businessInfo?.city || settings.business_city}`}
                {(businessInfo?.pincode || settings.business_pincode) && ` - ${businessInfo?.pincode || settings.business_pincode}`}
              </p>
              {(businessInfo?.phone || settings.business_phone) && <p className="text-sm">Phone: {businessInfo?.phone || settings.business_phone}</p>}
              {(businessInfo?.email || settings.business_email) && <p className="text-sm">Email: {businessInfo?.email || settings.business_email}</p>}
              {(businessInfo?.gstin || settings.business_gstin) && (
                <p className="text-sm font-mono font-semibold">GSTIN: {businessInfo?.gstin || settings.business_gstin}</p>
              )}
              {businessInfo?.pan && <p className="text-sm font-mono">PAN: {businessInfo.pan}</p>}
            </div>
            <div className="text-right">
              <h2 className="text-3xl font-bold text-primary">TAX INVOICE</h2>
              <p className="font-mono text-lg font-semibold mt-2">{invoice.invoice_number}</p>
              <p className="text-sm text-muted-foreground">
                Date: {new Date(invoice.invoice_date).toLocaleDateString("en-IN", { 
                  day: "2-digit", month: "short", year: "numeric" 
                })}
              </p>
              {invoice.is_inter_state !== undefined && (
                <Badge variant={invoice.is_inter_state ? "secondary" : "outline"} className="mt-2">
                  {invoice.is_inter_state ? "Inter-State (IGST)" : "Intra-State (CGST+SGST)"}
                </Badge>
              )}
            </div>
          </div>

          {/* Bill To / Ship From */}
          <div className="grid grid-cols-2 gap-8 mb-8">
            <div>
              <h3 className="font-semibold text-sm text-muted-foreground mb-2">BILL TO</h3>
              <p className="font-semibold">{invoice.customer_name}</p>
              {invoice.stores?.name && <p className="text-sm">{invoice.stores.name}</p>}
              {invoice.customer_address && <p className="text-sm whitespace-pre-line">{invoice.customer_address}</p>}
              {invoice.customer_phone && <p className="text-sm">Phone: {invoice.customer_phone}</p>}
              {invoice.customer_gstin && <p className="text-sm font-mono">GSTIN: {invoice.customer_gstin}</p>}
            </div>
            <div>
              <h3 className="font-semibold text-sm text-muted-foreground mb-2">DISPATCH FROM</h3>
              {invoice.warehouses ? (
                <>
                  <p className="font-semibold">{invoice.warehouses.name}</p>
                  <p className="text-sm whitespace-pre-line">
                    {invoice.warehouses.address}
                    {invoice.warehouses.city && `, ${invoice.warehouses.city}`}
                    {invoice.warehouses.pincode && ` - ${invoice.warehouses.pincode}`}
                  </p>
                  {invoice.warehouses.phone && <p className="text-sm">Phone: {invoice.warehouses.phone}</p>}
                </>
              ) : (
                <p className="text-sm text-muted-foreground">—</p>
              )}
            </div>
          </div>

          {/* Items Table */}
          <table className="w-full mb-6 text-sm">
            <thead>
              <tr className="bg-gray-100">
                <th className="text-left p-2 border">#</th>
                <th className="text-left p-2 border">Description</th>
                <th className="text-left p-2 border">HSN</th>
                <th className="text-right p-2 border">Qty</th>
                <th className="text-right p-2 border">Rate</th>
                <th className="text-right p-2 border">Taxable</th>
                <th className="text-right p-2 border">GST %</th>
                <th className="text-right p-2 border">Amount</th>
              </tr>
            </thead>
            <tbody>
              {invoice.invoice_items?.map((item: any, index: number) => {
                const lineTotal = item.quantity * item.unit_price;
                const gstRate = item.gst_rate || item.tax_rate || 0;
                const taxableAmt = item.taxable_amount || (gstRate > 0 ? lineTotal / (1 + gstRate / 100) : lineTotal);
                return (
                  <tr key={item.id}>
                    <td className="p-2 border">{index + 1}</td>
                    <td className="p-2 border">{item.product_name}</td>
                    <td className="p-2 border font-mono text-xs">{item.hsn_code || "—"}</td>
                    <td className="p-2 border text-right">{item.quantity}</td>
                    <td className="p-2 border text-right">₹{Number(item.unit_price).toLocaleString()}</td>
                    <td className="p-2 border text-right">₹{Number(taxableAmt).toLocaleString()}</td>
                    <td className="p-2 border text-right">{gstRate}%</td>
                    <td className="p-2 border text-right font-semibold">₹{Number(lineTotal).toLocaleString()}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>

          {/* GST Summary */}
          <div className="flex justify-end mb-8">
            <div className="w-80 border rounded-lg overflow-hidden">
              <div className="flex justify-between py-2 px-3 bg-gray-50 border-b">
                <span>Taxable Amount</span>
                <span className="font-medium">₹{Number(invoice.taxable_amount || invoice.subtotal).toLocaleString()}</span>
              </div>
              
              {/* Show CGST/SGST or IGST based on is_inter_state */}
              {invoice.is_inter_state ? (
                <div className="flex justify-between py-2 px-3 border-b">
                  <span>IGST {invoice.igst_rate ? `@ ${invoice.igst_rate}%` : ""}</span>
                  <span>₹{Number(invoice.igst_amount || invoice.tax_amount).toLocaleString()}</span>
                </div>
              ) : (
                <>
                  <div className="flex justify-between py-2 px-3 border-b">
                    <span>CGST {invoice.cgst_rate ? `@ ${invoice.cgst_rate}%` : ""}</span>
                    <span>₹{Number(invoice.cgst_amount || (invoice.tax_amount / 2)).toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between py-2 px-3 border-b">
                    <span>SGST {invoice.sgst_rate ? `@ ${invoice.sgst_rate}%` : ""}</span>
                    <span>₹{Number(invoice.sgst_amount || (invoice.tax_amount / 2)).toLocaleString()}</span>
                  </div>
                </>
              )}
              
              {Number(invoice.discount_amount) > 0 && (
                <div className="flex justify-between py-2 px-3 text-green-600 border-b">
                  <span>Discount</span>
                  <span>-₹{Number(invoice.discount_amount).toLocaleString()}</span>
                </div>
              )}
              <div className="flex justify-between py-3 px-3 bg-primary/10 font-bold text-lg">
                <span>Grand Total</span>
                <span>₹{Number(invoice.total_amount).toLocaleString()}</span>
              </div>
            </div>
          </div>

          {/* Amount in Words */}
          <div className="bg-gray-50 p-3 rounded mb-8">
            <p className="text-sm">
              <span className="font-semibold">Amount in Words: </span>
              {amountInWords}
            </p>
          </div>

          {/* Bank Details */}
          {(businessInfo?.bank_name || settings.bank_name) && (
            <div className="grid grid-cols-2 gap-8 mb-8">
              <div>
                <h3 className="font-semibold text-sm text-muted-foreground mb-2">BANK DETAILS</h3>
                <p className="text-sm">Bank: {businessInfo?.bank_name || settings.bank_name}</p>
                <p className="text-sm font-mono">A/C No: {businessInfo?.bank_account_number || settings.bank_account_number}</p>
                <p className="text-sm font-mono">IFSC: {businessInfo?.bank_ifsc || settings.bank_ifsc}</p>
                {(businessInfo?.bank_branch || settings.bank_branch) && <p className="text-sm">Branch: {businessInfo?.bank_branch || settings.bank_branch}</p>}
              </div>
              <div className="text-right">
                <h3 className="font-semibold text-sm text-muted-foreground mb-2">FOR {(businessInfo?.name || settings.business_name || "").toUpperCase()}</h3>
                <div className="h-16"></div>
                <p className="text-sm">Authorized Signatory</p>
              </div>
            </div>
          )}

          {/* Terms */}
          {settings.invoice_terms && (
            <div className="border-t pt-4">
              <h3 className="font-semibold text-sm text-muted-foreground mb-1">TERMS & CONDITIONS</h3>
              <p className="text-xs text-muted-foreground whitespace-pre-line">{settings.invoice_terms}</p>
            </div>
          )}

          {/* Linked Sales */}
          {invoice.invoice_sales?.length > 0 && (
            <div className="border-t pt-4 mt-4 print:hidden">
              <h3 className="font-semibold text-sm text-muted-foreground mb-2">LINKED SALES</h3>
              <div className="flex flex-wrap gap-2">
                {invoice.invoice_sales.map((link: any) => (
                  <Badge key={link.sale_id} variant="outline" className="font-mono">
                    {link.sales?.display_id || link.sale_id.slice(0, 8)}
                  </Badge>
                ))}
              </div>
            </div>
          )}

          {/* Notes */}
          {invoice.notes && (
            <div className="border-t pt-4 mt-4">
              <h3 className="font-semibold text-sm text-muted-foreground mb-1">NOTES</h3>
              <p className="text-sm whitespace-pre-line">{invoice.notes}</p>
            </div>
          )}
        </CardContent>
      </Card>

      <div className="hidden print:block print:space-y-8">
        {renderPrintCopy("Original Copy", false)}
        {renderPrintCopy("Customer Copy", true)}
      </div>

      <style>{`
        @media print {
          @page { margin: 12mm; }
          body { background: white !important; }
          .print\:hidden { display: none !important; }
          .print\:block { display: block !important; }
        }
      `}</style>
    </div>
  );
};

export default InvoiceView;

import { PageHeader } from "@/components/shared/PageHeader";
import { DataTable } from "@/components/shared/DataTable";
import { StatusBadge } from "@/components/shared/StatusBadge";
import { Badge } from "@/components/ui/badge";
import { Package, Pencil, X, Save, AlertTriangle, Grid3X3, Download, Tags, CheckSquare, DollarSign, Box } from "lucide-react";
import { ImageUpload } from "@/components/shared/ImageUpload";
import { ProductAccessMatrix } from "@/components/products/ProductAccessMatrix";
import { ProductCategories } from "@/components/products/ProductCategories";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { useAuth } from "@/contexts/AuthContext";
import { logActivity } from "@/lib/activityLogger";
import { Checkbox } from "@/components/ui/checkbox";
import { Loader2 } from "lucide-react";
import { useState, useMemo } from "react";
import { useIsMobile } from "@/hooks/use-mobile";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle,
} from "@/components/ui/dialog";
import { NoticeBox } from "@/components/shared/NoticeBox";
import {
  AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
  AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Textarea } from "@/components/ui/textarea";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { toast } from "sonner";
import { useQueryClient } from "@tanstack/react-query";

const Products = () => {
  const { user, role } = useAuth();
  const isMobile = useIsMobile();
  const canEdit = role === "super_admin" || role === "manager";
  const [showAdd, setShowAdd] = useState(false);
  const [showMatrix, setShowMatrix] = useState(false);
  const [showCategories, setShowCategories] = useState(false);
  const [editProduct, setEditProduct] = useState<any>(null);
  const [name, setName] = useState("");
  const [sku, setSku] = useState("");
  const [price, setPrice] = useState("");
  const [unit, setUnit] = useState("PCS");
  const [category, setCategory] = useState("");
  const [description, setDescription] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const [hsnCode, setHsnCode] = useState("");
  const [gstRate, setGstRate] = useState("18");
  const [saving, setSaving] = useState(false);
  const [selectMode, setSelectMode] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [confirmBulkDeactivate, setConfirmBulkDeactivate] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const qc = useQueryClient();

  const { data: products, isLoading } = useQuery({
    queryKey: ["products"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("products")
        .select("*")
        .order("created_at", { ascending: false });
      if (error) throw error;
      return data;
    },
  });

  const { data: categoryList } = useQuery({
    queryKey: ["product-categories"],
    queryFn: async () => {
      const { data, error } = await supabase
        .from("product_categories")
        .select("id, name")
        .order("name");
      if (error) throw error;
      return data || [];
    },
  });

  // Filter products based on search term
  const filteredProducts = useMemo(() => {
    if (!products) return [];
    if (!searchTerm.trim()) return products;
    const term = searchTerm.toLowerCase();
    return products.filter((p: any) => 
      p.name?.toLowerCase().includes(term) || 
      p.sku?.toLowerCase().includes(term) ||
      p.category?.toLowerCase().includes(term)
    );
  }, [products, searchTerm]);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    const { error } = await supabase.from("products").insert({
      name,
      sku,
      base_price: parseFloat(price) || 0,
      unit,
      category: category || null,
      description: description || null,
      image_url: imageUrl || null,
      hsn_code: hsnCode.trim() || null,
      gst_rate: parseFloat(gstRate) || 18,
      is_gst_inclusive: true,
    });
    setSaving(false);
    if (error) {
      toast.error(error.message);
    } else {
      toast.success("Product added");
      logActivity(user!.id, "Added product", "product", name);
      setShowAdd(false);
      resetForm();
      qc.invalidateQueries({ queryKey: ["products"] });
    }
  };

  const openEdit = (product: any) => {
    setEditProduct(product);
    setName(product.name || "");
    setSku(product.sku || "");
    setPrice(String(product.base_price || 0));
    setUnit(product.unit || "PCS");
    setCategory(product.category || "");
    setDescription(product.description || "");
    setImageUrl(product.image_url || "");
    setHsnCode(product.hsn_code || "");
    setGstRate(String(product.gst_rate || 18));
  };

  const handleEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editProduct) return;
    setSaving(true);
    const { error } = await supabase.from("products").update({
      name,
      sku,
      base_price: parseFloat(price) || 0,
      unit,
      category: category || null,
      description: description || null,
      image_url: imageUrl || null,
      hsn_code: hsnCode.trim() || null,
      gst_rate: parseFloat(gstRate) || 18,
    }).eq("id", editProduct.id);
    setSaving(false);
    if (error) {
      toast.error(error.message);
    } else {
      toast.success("Product updated");
      logActivity(user!.id, "Updated product", "product", name, editProduct.id);
      setEditProduct(null);
      resetForm();
      qc.invalidateQueries({ queryKey: ["products"] });
    }
  };

  const handleToggleActive = async (product: any) => {
    const newVal = !product.is_active;
    const { error } = await supabase.from("products").update({ is_active: newVal }).eq("id", product.id);
    if (error) {
      toast.error(error.message);
      return;
    }
    toast.success(`Product ${newVal ? "activated" : "deactivated"}`);
    qc.invalidateQueries({ queryKey: ["products"] });
  };

  const resetForm = () => {
    setName(""); setSku(""); setPrice(""); setUnit("PCS"); setCategory(""); setDescription(""); setImageUrl(""); setHsnCode(""); setGstRate("18");
  };

  const toggleSelect = (id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      next.has(id) ? next.delete(id) : next.add(id);
      return next;
    });
  };

  const handleBulkStatus = async (activate: boolean) => {
    const ids = Array.from(selectedIds);
    if (!ids.length) return;
    const { error } = await supabase.from("products").update({ is_active: activate }).in("id", ids);
    if (error) { toast.error(error.message); return; }
    toast.success(`${ids.length} product(s) ${activate ? "activated" : "deactivated"}`);
    setSelectedIds(new Set());
    setSelectMode(false);
    qc.invalidateQueries({ queryKey: ["products"] });
  };

  const columns = [
    ...(selectMode ? [{
      header: "",
      accessor: (row: any) => (
        <Checkbox
          checked={selectedIds.has(row.id)}
          onCheckedChange={() => toggleSelect(row.id)}
          onClick={(e: React.MouseEvent) => e.stopPropagation()}
        />
      ),
      className: "w-10",
    }] : []),
    { header: "Product", accessor: (row: any) => (
      <div className="flex items-center gap-2">
        {row.image_url && <img src={row.image_url} alt="" loading="lazy" className="h-8 w-8 rounded-md object-cover" />}
        <span className="font-medium">{row.name}</span>
      </div>
    )},
    { header: "SKU", accessor: "sku" as const, className: "font-mono text-xs text-muted-foreground hidden sm:table-cell" },
    { header: "Category", accessor: (row: any) => row.category ? <Badge variant="secondary">{row.category}</Badge> : <span className="text-muted-foreground">—</span>, className: "hidden md:table-cell" },
    { header: "Base Price", accessor: (row: any) => `₹${Number(row.base_price).toLocaleString()}` },
    { header: "Unit", accessor: "unit" as const, className: "hidden sm:table-cell" },
    { header: "Status", accessor: (row: any) => (
      <div className="flex items-center gap-2">
        <StatusBadge status={row.is_active ? "active" : "inactive"} />
        {canEdit && (
          <Switch
            checked={row.is_active}
            onCheckedChange={() => handleToggleActive(row)}
            className="scale-75"
          />
        )}
      </div>
    )},
    ...(canEdit ? [{
      header: "Actions",
      accessor: (row: any) => (
        <Button variant="ghost" size="sm" className="h-7 text-xs gap-1" onClick={(e: React.MouseEvent) => { e.stopPropagation(); openEdit(row); }}>
          <Pencil className="h-3 w-3" /> Edit
        </Button>
      ),
      hideOnMobile: true,
    }] : []),
  ];

  if (isLoading) {
    return <div className="flex items-center justify-center py-20"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>;
  }

  if (showMatrix) {
    return <ProductAccessMatrix onBack={() => setShowMatrix(false)} />;
  }

  if (showCategories) {
    return <ProductCategories onBack={() => setShowCategories(false)} />;
  }

  return (
    <div className="space-y-6 animate-fade-in">
      <PageHeader
        title="Products"
        subtitle="Manage your product catalog and pricing"
        primaryAction={{ label: "Add Product", onClick: () => { resetForm(); setShowAdd(true); } }}
        actions={[
          { label: "Categories", icon: Tags, onClick: () => setShowCategories(true), priority: 1 },
          { label: "Product Access", icon: Grid3X3, onClick: () => setShowMatrix(true), priority: 2 },
          ...(canEdit ? [{ label: selectMode ? "Done" : "Select", icon: CheckSquare, onClick: () => { setSelectMode((v) => !v); setSelectedIds(new Set()); }, priority: 3 }] : []),
        ]}
      />

      {selectMode && selectedIds.size > 0 && (
        <NoticeBox
          variant="premium"
          message={
            <div className="flex flex-wrap items-center gap-2 w-full">
              <span className="font-semibold">{selectedIds.size} selected</span>
              <div className="flex gap-2 ml-3">
                <Button size="sm" variant="outline" className="h-8 bg-background text-green-600 border-green-600/40" onClick={() => handleBulkStatus(true)}>Activate</Button>
                <Button size="sm" variant="outline" className="h-8 bg-background text-destructive border-destructive/40" onClick={() => setConfirmBulkDeactivate(true)}>Deactivate</Button>
                <Button size="sm" variant="ghost" className="h-8 ml-auto" onClick={() => setSelectedIds(new Set())}>Clear</Button>
              </div>
            </div>
          }
        />
      )}

      {/* Desktop: Card Grid, Mobile: DataTable */}
      {!isMobile ? (
        <div className="space-y-4">
          {/* Search bar for desktop */}
          <Input 
            placeholder="Search products..." 
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="max-w-sm"
          />
          
          <div className="entity-grid">
            {filteredProducts.map((row: any) => (
              <div
                key={row.id}
                onClick={() => { if (selectMode) { toggleSelect(row.id); } else if (canEdit) { openEdit(row); } }}
                className={`group entity-card ${!row.is_active ? "entity-card-inactive" : ""} ${selectedIds.has(row.id) ? "entity-card-selected" : ""}`}
              >
                {/* Header with image */}
                <div className="entity-card-header !h-36">
                  {row.image_url ? (
                    <img src={row.image_url} alt={row.name} loading="lazy" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-200" />
                  ) : (
                    <Package className="h-12 w-12 text-muted-foreground/30" />
                  )}
                  <div className="absolute top-2 right-2 flex items-center gap-2">
                    {selectMode && (
                      <Checkbox 
                        checked={selectedIds.has(row.id)}
                        onClick={(e: React.MouseEvent) => { e.stopPropagation(); toggleSelect(row.id); }}
                        className="bg-background"
                      />
                    )}
                    <StatusBadge status={row.is_active ? "active" : "inactive"} />
                  </div>
                </div>

                {/* Content */}
                <div className="entity-card-content">
                  <div>
                    <h3 className="entity-card-title">{row.name}</h3>
                    <p className="entity-card-subtitle mt-0.5">{row.sku}</p>
                  </div>

                  {row.category && (
                    <Badge variant="secondary" className="text-xs">{row.category}</Badge>
                  )}

                  {/* HSN and GST info */}
                  {(row.hsn_code || row.gst_rate) && (
                    <div className="flex items-center gap-2 text-xs text-muted-foreground">
                      {row.hsn_code && <span>HSN: {row.hsn_code}</span>}
                      {row.gst_rate && <span className="bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded font-medium">{row.gst_rate}% GST</span>}
                    </div>
                  )}

                  {/* Price and unit */}
                  <div className="entity-card-stat">
                    <div className="flex items-center gap-1.5 text-muted-foreground">
                      <Box className="h-3.5 w-3.5" />
                      <span className="text-xs">{row.unit}</span>
                    </div>
                    <div className="text-right">
                      <p className="entity-card-label">Price (incl. GST)</p>
                      <p className="font-bold text-foreground">₹{Number(row.base_price).toLocaleString()}</p>
                    </div>
                  </div>

                  {/* Actions */}
                  {canEdit && (
                    <div className="pt-2 border-t flex items-center justify-between">
                      <Switch
                        checked={row.is_active}
                        onCheckedChange={() => handleToggleActive(row)}
                        onClick={(e: React.MouseEvent) => e.stopPropagation()}
                        className="scale-90"
                      />
                      <Button 
                        variant="ghost" 
                        size="sm" 
                        className="h-8 text-xs gap-1.5"
                        onClick={(e: React.MouseEvent) => { e.stopPropagation(); openEdit(row); }}
